import { allFiches } from '../allData'

const ficheQuestions = allFiches.flatMap((fiche) =>
  (fiche.quiz || []).map((q, i) => ({
    id: `fiche_${fiche.id}_${i}`,
    level: fiche.level,
    theme: fiche.theme,
    difficulty: q.difficulty || 1,
    points: q.points || 10,
    ...q,
  }))
)

const staticQuestions = [
  // ========== 6ème ==========
  { id: 'q_6e_01', level: '6e', theme: 'Préhistoire', question: "Quelle est la principale caractéristique de l'homo sapiens par rapport aux autres hominidés ?", options: ["Il est le premier à utiliser le feu", "C'est l'espèce humaine actuelle, apparue il y a ~300 000 ans en Afrique", "Il est le premier à fabriquer des outils", "Il vit uniquement dans les cavernes"], answer: "C'est l'espèce humaine actuelle, apparue il y a ~300 000 ans en Afrique", explanation: "Homo sapiens (homme 'sage') est l'espèce humaine moderne. Il apparaît en Afrique orientale il y a environ 300 000 ans et colonise progressivement toute la planète. Il est caractérisé par un cerveau volumineux, un langage articulé complexe et une capacité d'abstraction.", difficulty: 1 },
  { id: 'q_6e_02', level: '6e', theme: 'Préhistoire', question: "Qu'est-ce que la révolution néolithique ?", options: ["L'invention de l'écriture", "Le passage d'une économie de chasse-cueillette à l'agriculture et l'élevage", "La fabrication des premiers outils en métal", "L'apparition de l'homo sapiens"], answer: "Le passage d'une économie de chasse-cueillette à l'agriculture et l'élevage", explanation: "La révolution néolithique (vers 10 000 av. J.-C., d'abord au Moyen-Orient) marque le passage de l'économie de prédation (chasse, cueillette) à l'économie de production (agriculture, élevage). Elle entraîne la sédentarisation, les premiers villages, puis les premières villes.", difficulty: 1 },
  { id: 'q_6e_03', level: '6e', theme: 'Mésopotamie', question: "Qu'est-ce que la Mésopotamie et pourquoi y naissent les premières villes ?", options: ["Une région d'Afrique du Nord, fertile grâce au Nil", "La région entre le Tigre et l'Euphrate (Irak actuel), fertile et irriguée — berceau des premières civilisations", "Une île de la Méditerranée, centre du commerce phénicien", "La plaine de l'Indus, en Asie du Sud"], answer: "La région entre le Tigre et l'Euphrate (Irak actuel), fertile et irriguée — berceau des premières civilisations", explanation: "La Mésopotamie ('entre les fleuves' en grec) est la région entre le Tigre et l'Euphrate, dans l'actuel Irak. L'irrigation des terres grâce à ces deux fleuves permet une agriculture abondante et un surplus alimentaire. Ce surplus permet la spécialisation des métiers et l'émergence des premières villes (Uruk, vers -4000 av. J.-C.).", difficulty: 1 },
  { id: 'q_6e_04', level: '6e', theme: 'Mésopotamie', question: "Qu'est-ce que le Code de Hammurabi ?", options: ["Un traité de paix entre Égypte et Assyrie", "Le premier code de lois écrit de l'Histoire (~1750 av. J.-C.)", "Une liste des pharaons égyptiens", "Un texte religieux sumérien"], answer: "Le premier code de lois écrit de l'Histoire (~1750 av. J.-C.)", explanation: "Le Code de Hammurabi (roi de Babylone, ~1750 av. J.-C.) est l'un des premiers codes de lois écrits. Gravé sur une stèle de 2,25m, il contient 282 lois régissant la vie sociale : commerce, famille, salaires, délits. Principe : la peine doit être proportionnelle au crime ('œil pour œil, dent pour dent').", difficulty: 2 },
  { id: 'q_6e_05', level: '6e', theme: 'Égypte antique', question: "Qu'est-ce qu'un pharaon dans la civilisation égyptienne ?", options: ["Un prêtre chargé des cérémonies religieuses", "Le roi-dieu d'Égypte, intermédiaire entre les hommes et les dieux, maître absolu du pays", "Un général en chef de l'armée égyptienne", "Un haut fonctionnaire chargé de l'administration"], answer: "Le roi-dieu d'Égypte, intermédiaire entre les hommes et les dieux, maître absolu du pays", explanation: "Le pharaon est à la fois roi et dieu en Égypte antique. Il est considéré comme le fils de Rê (dieu soleil) et l'incarnation d'Horus. Il possède tous les pouvoirs (politique, religieux, militaire, juridique). À sa mort, il devient Osiris. Sa double couronne rouge (Basse-Égypte) et blanche (Haute-Égypte) symbolise l'unité du pays.", difficulty: 1 },
  { id: 'q_6e_06', level: '6e', theme: 'Grèce antique', question: "Qu'est-ce qu'une polis grecque ?", options: ["Un territoire agricole de la Grèce antique", "Une cité-État indépendante, unité politique de base de la Grèce antique", "Un quartier d'Athènes consacré aux marchands", "Une forteresse militaire sur une colline"], answer: "Une cité-État indépendante, unité politique de base de la Grèce antique", explanation: "La polis (cité-État) est la forme d'organisation politique fondamentale de la Grèce antique. Chaque polis est une communauté de citoyens (hommes libres adultes) organisée autour d'une ville et de son territoire. Athènes et Sparte sont les plus célèbres. Elles sont jalousement indépendantes les unes des autres.", difficulty: 1 },
  { id: 'q_6e_07', level: '6e', theme: 'Démocratie athénienne', question: "Qui invente la démocratie athénienne au Ve siècle av. J.-C. ?", options: ["Platon", "Périclès (et ses prédécesseurs Solon et Clisthène)", "Alexandre le Grand", "Socrate"], answer: "Périclès (et ses prédécesseurs Solon et Clisthène)", explanation: "La démocratie athénienne est le fruit de plusieurs réformes : Solon (-594) réduit la dette et élargit la participation politique ; Clisthène (-508) réorganise la cité en tribus et fonde la démocratie ; Périclès (-461 à -429) la consolide en étendant la participation et en rémunérant les magistrats (misthos).", difficulty: 2 },
  { id: 'q_6e_08', level: '6e', theme: 'Rome antique', question: "Quelle est la différence entre la République et l'Empire romains ?", options: ["La République est dirigée par un roi, l'Empire par le Sénat", "La République est gouvernée par des magistrats élus, l'Empire par un empereur", "La République est pacifique, l'Empire fait des conquêtes", "La République correspond aux origines de Rome, l'Empire à la fin"], answer: "La République est gouvernée par des magistrats élus, l'Empire par un empereur", explanation: "La République romaine (509-27 av. J.-C.) est gouvernée par des magistrats élus (consuls, préteurs) et le Sénat. L'Empire commence avec Auguste (-27 av. J.-C.) : le pouvoir est concentré dans les mains d'un seul homme (l'Emperor/Imperator). La forme républicaine est maintenue (le Sénat continue) mais vidée de sa substance.", difficulty: 1 },
  { id: 'q_6e_09', level: '6e', theme: 'Christianisme', question: "En quelle année le christianisme devient-il la religion officielle de l'Empire romain ?", options: ["33 ap. J.-C.", "313 ap. J.-C.", "380 ap. J.-C.", "476 ap. J.-C."], answer: "380 ap. J.-C.", explanation: "En 313, l'édit de Milan (Constantin) accorde la liberté religieuse aux chrétiens. C'est l'édit de Thessalonique de 380 (Théodose Ier) qui fait du christianisme la religion d'État de l'Empire. Désormais, les autres cultes sont interdits. Ce tournant aura des conséquences durables sur l'histoire mondiale.", difficulty: 3 },
  { id: 'q_6e_10', level: '6e', theme: 'Islam', question: "Quelle est la date de l'Hégire et pourquoi est-elle fondamentale ?", options: ["622 ap. J.-C. — c'est l'an 1 du calendrier musulman, marquant la fondation de la communauté islamique à Médine", "610 ap. J.-C. — c'est la première révélation de Mohammed", "632 ap. J.-C. — c'est la mort de Mohammed", "630 ap. J.-C. — c'est la prise de La Mecque"], answer: "622 ap. J.-C. — c'est l'an 1 du calendrier musulman, marquant la fondation de la communauté islamique à Médine", explanation: "L'Hégire (622 ap. J.-C.) est la migration de Muhammad de La Mecque (où il est persécuté) à Médine. À Médine, il fonde la première communauté islamique (umma) et établit les règles politiques et religieuses de l'islam. C'est pourquoi 622 est l'an 1 du calendrier hégirien.", difficulty: 2 },

  // ========== 5ème ==========
  { id: 'q_5e_01', level: '5e', theme: 'Moyen Âge', question: "Qu'est-ce que la féodalité ?", options: ["Un système économique basé sur le commerce", "Un système politique basé sur des liens de dépendance personnelle (vassalité) et la possession de fiefs", "Un régime politique dirigé par un roi absolu", "Un mouvement religieux du Moyen Âge"], answer: "Un système politique basé sur des liens de dépendance personnelle (vassalité) et la possession de fiefs", explanation: "La féodalité est le système social et politique dominant en Europe occidentale au Moyen Âge. Elle repose sur : 1) des liens personnels de vassal à seigneur (hommage, fidélité, service militaire) ; 2) l'attribution d'un fief (terre) en échange de ces services. La pyramide féodale va du serf au roi.", difficulty: 1 },
  { id: 'q_5e_02', level: '5e', theme: 'Croisades', question: "Pourquoi les croisades sont-elles lancées à partir de 1095 ?", options: ["Pour évangéliser les peuples d'Asie", "Pour reconquérir Jérusalem et la Terre Sainte des mains des musulmans", "Pour commercer avec les pays d'Orient", "Pour combattre les hérésies chrétiennes"], answer: "Pour reconquérir Jérusalem et la Terre Sainte des mains des musulmans", explanation: "En 1095, le pape Urbain II lance la 1ère croisade au Concile de Clermont pour répondre à l'appel de l'Empereur byzantin et reconquérir Jérusalem, passée sous contrôle turc-seldjoukide (1071). Il promet l'indulgence plénière à ceux qui partent. La 1ère croisade aboutit à la prise de Jérusalem (1099).", difficulty: 2 },
  { id: 'q_5e_03', level: '5e', theme: 'Moyen Âge', question: "Qu'est-ce que la Reconquista en Espagne ?", options: ["La conquête de l'Amérique par les Espagnols", "La reconquête progressive de la péninsule ibérique par les royaumes chrétiens contre les musulmans (711-1492)", "La guerre entre la Castille et le Portugal au XVe siècle", "La persécution des Juifs en Espagne"], answer: "La reconquête progressive de la péninsule ibérique par les royaumes chrétiens contre les musulmans (711-1492)", explanation: "La Reconquista est la reconquête de l'Espagne par les royaumes chrétiens (Castille, León, Aragon, Portugal) face aux dynasties musulmanes qui avaient conquis la péninsule ibérique depuis 711. Elle s'achève en 1492 avec la prise de Grenade par Isabelle de Castille et Ferdinand d'Aragon.", difficulty: 2 },
  { id: 'q_5e_04', level: '5e', theme: 'Renaissance', question: "Qu'est-ce que l'imprimerie à caractères mobiles (Gutenberg, ~1450) change pour la société ?", options: ["Elle permet de construire des cathédrales plus vite", "Elle révolutionne la diffusion des idées en permettant la reproduction massive et rapide de textes", "Elle remplace les scribes dans les monastères uniquement", "Elle n'a d'impact que sur la religion"], answer: "Elle révolutionne la diffusion des idées en permettant la reproduction massive et rapide de textes", explanation: "L'imprimerie de Gutenberg (~1450) révolutionne la communication : un livre imprimé coûte 10 fois moins cher qu'un manuscrit copié à la main. La Bible de Gutenberg (1455) est tirée à 180 exemplaires. En 50 ans, 12 millions de livres sont imprimés. Cette diffusion massive des idées est essentielle à la Renaissance et à la Réforme protestante.", difficulty: 2 },
  { id: 'q_5e_05', level: '5e', theme: 'Grandes Découvertes', question: "Quel empire Hernán Cortés détruit-il entre 1519 et 1521 ?", options: ["L'Empire inca au Pérou", "L'Empire aztèque au Mexique", "L'Empire maya au Yucatán", "L'Empire olmèque en Amérique centrale"], answer: "L'Empire aztèque au Mexique", explanation: "Hernán Cortés débarque au Mexique avec 500 conquistadors en 1519. Grâce aux épidémies (variole), aux alliés indigènes (Tlaxcaltèques) et à la supériorité technologique (chevaux, armes à feu), il conquiert l'Empire aztèque de Moctezuma II et capture Tenochtitlan (futur Mexico) en 1521. La population mexicaine passe de 25 à 2 millions en un siècle.", difficulty: 2 },
  { id: 'q_5e_06', level: '5e', theme: 'Réforme protestante', question: "Que remet en cause Luther dans ses 95 Thèses (1517) ?", options: ["L'autorité du roi de France", "La vente des indulgences et les abus de l'Église catholique", "L'existence de Dieu", "Le pouvoir du Pape uniquement sur les affaires politiques"], answer: "La vente des indulgences et les abus de l'Église catholique", explanation: "Le 31 octobre 1517, Luther affiche ses 95 thèses à la porte de l'église de Wittenberg. Il conteste principalement la vente des indulgences (des certificats censés réduire le séjour au purgatoire, vendus pour financer la basilique Saint-Pierre à Rome). Luther affirme que le salut vient de la foi seule (sola fide), pas des œuvres ou des achats.", difficulty: 2 },
  { id: 'q_5e_07', level: '5e', theme: 'Islam médiéval', question: "Quel est le rôle de Bagdad dans le monde arabo-musulman du IXe siècle ?", options: ["Une ville fortifiée militaire sur la frontière byzantine", "La capitale du califat abbasside, premier centre intellectuel et commercial du monde", "Le lieu saint de l'islam, comme La Mecque", "Une cité marchande sur les côtes de la mer Rouge"], answer: "La capitale du califat abbasside, premier centre intellectuel et commercial du monde", explanation: "Fondée en 762, Bagdad est la capitale du califat abbasside. À son apogée au IXe siècle, elle compte 1 à 2 millions d'habitants (la plus grande ville du monde). La Maison de la Sagesse (Bayt al-Hikma) traduit et enrichit les textes grecs, indiens et perses. Elle est le centre du monde en mathématiques, médecine, astronomie et philosophie.", difficulty: 3 },
  { id: 'q_5e_08', level: '5e', theme: 'Guerre de Cent Ans', question: "À quelle bataille Jeanne d'Arc est-elle associée pour avoir sauvé Orléans ?", options: ["La bataille d'Azincourt", "Le siège d'Orléans (1429)", "La bataille de Poitiers", "La bataille de Crécy"], answer: "Le siège d'Orléans (1429)", explanation: "Orléans est assiégée par les Anglais depuis octobre 1428. Jeanne d'Arc convainc Charles VII de lui confier des troupes. Le 8 mai 1429, elle et ses soldats libèrent Orléans. C'est un tournant décisif de la Guerre de Cent Ans. La victoire galvanise les Français et permet le sacre de Charles VII à Reims (17 juillet 1429).", difficulty: 1 },
  { id: 'q_5e_09', level: '5e', theme: 'Charlemagne', question: "Qui couronne Charlemagne Empereur d'Occident le 25 décembre 800 ?", options: ["Le roi des Francs lui-même", "Le pape Léon III à Rome", "Le Sénat de Constantinople", "Le roi des Saxons"], answer: "Le pape Léon III à Rome", explanation: "Le 25 décembre 800, lors de la messe de Noël à Saint-Pierre de Rome, le pape Léon III pose la couronne impériale sur la tête de Charlemagne. Ce sacre marque la renaissance de l'Empire d'Occident et établit une alliance durable entre le pouvoir politique des Francs et l'autorité religieuse de la papauté.", difficulty: 1 },

  // ========== 4ème ==========
  { id: 'q_4e_01', level: '4e', theme: 'Révolution française', question: "Quels sont les 3 ordres de la société d'Ancien Régime français ?", options: ["Noblesse, Bourgeoisie, Peuple", "Clergé, Noblesse, Tiers-État", "Roi, Seigneurs, Paysans", "Patriciens, Plébéiens, Esclaves"], answer: "Clergé, Noblesse, Tiers-État", explanation: "La société française d'Ancien Régime est divisée en 3 ordres : 1er ordre = Clergé (~100 000 personnes, exemptés d'impôts) ; 2e ordre = Noblesse (~400 000, privilégiés) ; 3e Tiers-État = tous les autres (~28 millions de personnes). Les États Généraux convoqués en mai 1789 rassemblent ces 3 ordres.", difficulty: 1 },
  { id: 'q_4e_02', level: '4e', theme: 'Révolution française', question: "Que se passe-t-il le 14 juillet 1789 ?", options: ["La réunion des États Généraux", "La prise de la Bastille par les Parisiens", "La fuite de Louis XVI à Varennes", "La Déclaration des Droits de l'Homme et du Citoyen"], answer: "La prise de la Bastille par les Parisiens", explanation: "Le 14 juillet 1789, les Parisiens prennent d'assaut la Bastille, prison royale symbole du despotisme. C'est le début de la Révolution dans les rues. La Bastille ne contient que 7 prisonniers, mais sa prise symbolise le renversement de l'absolutisme. C'est devenu la fête nationale française.", difficulty: 1 },
  { id: 'q_4e_03', level: '4e', theme: 'Révolution industrielle', question: "Quelle invention est au cœur de la révolution industrielle britannique ?", options: ["La dynamite (Alfred Nobel)", "La machine à vapeur (perfectionnée par James Watt, 1769)", "L'électricité (Edison)", "Le moteur à explosion (Benz)"], answer: "La machine à vapeur (perfectionnée par James Watt, 1769)", explanation: "La machine à vapeur de James Watt (1769) est l'invention-clé de la première révolution industrielle. Elle transforme l'énergie thermique en énergie mécanique, permettant de motoriser les machines dans les filatures, les mines et les chemins de fer. Elle remplace la force humaine et animale et permet la production de masse.", difficulty: 1 },
  { id: 'q_4e_04', level: '4e', theme: 'Lumières', question: "Quel est le principe fondamental que Montesquieu défend dans L'Esprit des lois (1748) ?", options: ["La monarchie absolue de droit divin", "La séparation des pouvoirs (exécutif, législatif, judiciaire)", "La révolution populaire contre les rois", "L'égalité naturelle de tous les hommes"], answer: "La séparation des pouvoirs (exécutif, législatif, judiciaire)", explanation: "Montesquieu (L'Esprit des lois, 1748) théorise la séparation des pouvoirs : pour qu'on ne puisse abuser du pouvoir, il faut que le pouvoir arrête le pouvoir. Il distingue 3 pouvoirs : exécutif (gouverner), législatif (faire les lois), judiciaire (appliquer les lois). Chaque pouvoir doit contrôler les autres. Base des constitutions démocratiques modernes.", difficulty: 2 },
  { id: 'q_4e_05', level: '4e', theme: 'Napoléon', question: "Quelle est l'importance du Code civil napoléonien (1804) ?", options: ["Il abolit la monarchie en France", "Il unifie le droit français, garantit l'égalité civile et est toujours en vigueur dans ses grandes lignes", "Il crée la Légion d'Honneur", "Il établit la Constitution de la Ve République"], answer: "Il unifie le droit français, garantit l'égalité civile et est toujours en vigueur dans ses grandes lignes", explanation: "Le Code civil (1804) unifie les 400 coutumes juridiques locales de France en un corpus cohérent de lois. Il garantit l'égalité civile, la liberté contractuelle et la propriété privée. Exporté dans toute l'Europe napoléonienne, il influence encore le droit de nombreux pays. En France, il est toujours la base du droit civil.", difficulty: 2 },
  { id: 'q_4e_06', level: '4e', theme: 'Grandes Découvertes', question: "Quel était l'objectif initial de Christophe Colomb quand il part en 1492 ?", options: ["Découvrir un nouveau continent (l'Amérique)", "Atteindre les Indes (Asie) par une route maritime vers l'Ouest", "Contourner l'Afrique par le sud", "Établir une colonie sur les îles Canaries"], answer: "Atteindre les Indes (Asie) par une route maritime vers l'Ouest", explanation: "Colomb cherche une route occidentale vers les Indes (Chine, Japon, Inde) pour s'affranchir des routes terrestres (monopole ottoman). Il pense que la Terre est ronde mais en sous-estime la taille. Il atteint les Caraïbes le 12 octobre 1492 et croit avoir atteint l'Asie jusqu'à sa mort. C'est Amerigo Vespucci qui comprendra que c'est un nouveau continent.", difficulty: 1 },
  { id: 'q_4e_07', level: '4e', theme: 'Louis XIV', question: "Pourquoi Louis XIV construit-il Versailles ?", options: ["Pour fuir les épidémies de Paris", "Pour concentrer la noblesse près de lui et la contrôler, symbole de sa puissance absolue", "Pour s'éloigner du pape et de Rome", "Pour surveiller les frontières du royaume"], answer: "Pour concentrer la noblesse près de lui et la contrôler, symbole de sa puissance absolue", explanation: "Louis XIV déplace sa cour de Paris à Versailles (à partir de 1682). Cette décision est politique : en réunissant la noblesse à Versailles, il la sort de ses fiefs, la tient sous surveillance, la plonge dans les intrigues et les dépenses de cour. La noblesse perd ainsi toute influence politique réelle. Versailles est aussi le symbole de la puissance royale française.", difficulty: 2 },

  // ========== 3ème ==========
  { id: 'q_3e_01', level: '3e', theme: 'Première Guerre mondiale', question: "Quels sont les deux blocs qui s'affrontent pendant la Première Guerre mondiale ?", options: ["Alliés (France, Royaume-Uni, Russie, USA) contre Empires centraux (Allemagne, Autriche-Hongrie, Empire ottoman)", "France et Angleterre contre Allemagne et Russie", "USA et France contre Allemagne et Japon", "Russie et Allemagne contre France et Angleterre"], answer: "Alliés (France, Royaume-Uni, Russie, USA) contre Empires centraux (Allemagne, Autriche-Hongrie, Empire ottoman)", explanation: "La Première Guerre mondiale oppose la Triple Entente (France, Royaume-Uni, Russie + Italie depuis 1915, USA depuis 1917) aux Empires centraux (Allemagne, Autriche-Hongrie, Empire ottoman + Bulgarie). 18 à 20 millions de morts. La guerre se termine le 11 novembre 1918 par l'armistice.", difficulty: 1 },
  { id: 'q_3e_02', level: '3e', theme: 'Révolution russe', question: "Que se passe-t-il en octobre 1917 en Russie ?", options: ["Le tsar Nicolas II abdique", "Les bolcheviks de Lénine prennent le pouvoir lors d'un coup d'État", "La Russie signe la paix avec l'Allemagne", "La Russie entre en guerre contre le Japon"], answer: "Les bolcheviks de Lénine prennent le pouvoir lors d'un coup d'État", explanation: "La révolution d'Octobre (25 octobre 1917, calendrier julien / 7 novembre calendrier grégorien) est un coup d'État bolchevik. Les gardes rouges prennent le palais d'Hiver à Petrograd. Lénine renverse le gouvernement provisoire (Kerenski) et fonde la République soviétique. En janvier 1918, il signe la paix de Brest-Litovsk avec l'Allemagne.", difficulty: 2 },
  { id: 'q_3e_03', level: '3e', theme: 'Nazisme', question: "Qu'est-ce que la 'Nuit de Cristal' (novembre 1938) ?", options: ["Une bataille de la Seconde Guerre mondiale", "Un pogrom organisé par les nazis : synagogues brûlées, Juifs tués et déportés", "La destruction de la ligne Maginot", "Un accord diplomatique entre Hitler et Staline"], answer: "Un pogrom organisé par les nazis : synagogues brûlées, Juifs tués et déportés", explanation: "La Nuit de Cristal (9-10 novembre 1938) est un pogrom organisé par les SS et les SA sous prétexte d'un attentat contre un diplomate allemand à Paris. 7 500 commerces juifs saccagés, 1 400 synagogues incendiées, 91 morts, 30 000 Juifs arrêtés. Elle marque l'escalade des persécutions antisémites avant la Shoah.", difficulty: 2 },
  { id: 'q_3e_04', level: '3e', theme: 'Seconde Guerre mondiale', question: "Qu'est-ce que la 'Solution finale' (Wannsee, janvier 1942) ?", options: ["Un plan de reddition de l'Allemagne", "La décision nazie d'exterminer systématiquement tous les Juifs d'Europe", "Un accord de paix entre l'Allemagne et l'URSS", "Un plan de déportation des Juifs vers Madagascar"], answer: "La décision nazie d'exterminer systématiquement tous les Juifs d'Europe", explanation: "La conférence de Wannsee (20 janvier 1942, Berlin) réunit 15 hauts fonctionnaires nazis pour organiser la 'Solution finale à la question juive' : l'extermination systématique de tous les Juifs d'Europe. Des camps d'extermination (Auschwitz-Birkenau, Treblinka, Sobibor) sont construits en Pologne occupée. Résultat : 6 millions de Juifs tués.", difficulty: 2 },
  { id: 'q_3e_05', level: '3e', theme: 'Résistance', question: "Qu'est-ce que le Conseil National de la Résistance (CNR, 1943) ?", options: ["Un gouvernement en exil à Londres", "L'unification de tous les mouvements de résistance intérieure française sous l'autorité de de Gaulle", "Une organisation créée par Pétain pour lutter contre les résistants", "L'alliance entre la France Libre et les États-Unis"], answer: "L'unification de tous les mouvements de résistance intérieure française sous l'autorité de de Gaulle", explanation: "Le CNR, fondé le 27 mai 1943 à Paris par Jean Moulin, réunit pour la première fois tous les mouvements de résistance (Combat, Franc-Tireur, Libération-Nord, libération-Sud), les partis politiques (PCF, SFIO) et les syndicats sous l'autorité du général de Gaulle. Il adopte un programme de reconstruction de la France après la Libération.", difficulty: 2 },
  { id: 'q_3e_06', level: '3e', theme: 'Guerre Froide', question: "Qu'est-ce que la crise des missiles de Cuba (1962) ?", options: ["La révolution castriste à Cuba", "13 jours au bord de la guerre nucléaire entre USA et URSS à propos de missiles soviétiques installés à Cuba", "L'invasion américaine de Cuba (Baie des Cochons)", "L'embargo économique américain contre Cuba"], answer: "13 jours au bord de la guerre nucléaire entre USA et URSS à propos de missiles soviétiques installés à Cuba", explanation: "En octobre 1962, les USA découvrent que l'URSS installe des missiles nucléaires à Cuba (à 150 km de la Floride). Kennedy impose un blocus naval. 13 jours de tension extrême (22-28 octobre) : la guerre nucléaire est évitée grâce au compromis Kennedy-Khrouchtchev (retrait des missiles soviétiques contre promesse USA de ne pas envahir Cuba). Création du 'téléphone rouge'.", difficulty: 2 },
  { id: 'q_3e_07', level: '3e', theme: 'Décolonisation', question: "Quelle est la signification de la Conférence de Bandung (1955) ?", options: ["Un accord commercial entre pays d'Asie", "La première rencontre des États décolonisés (Asie, Afrique), fondement du mouvement des non-alignés", "Une alliance militaire contre la France et le Royaume-Uni", "Une conférence de l'ONU sur la décolonisation"], answer: "La première rencontre des États décolonisés (Asie, Afrique), fondement du mouvement des non-alignés", explanation: "La Conférence de Bandung (18-24 avril 1955, Indonésie) réunit 29 États africains et asiatiques représentant 1,5 milliard de personnes. Elle affirme les principes de coexistence pacifique, la condamnation du colonialisme et la neutralité face aux deux blocs. Elle fonde le mouvement des non-alignés (1961, Belgrade).", difficulty: 3 },
  { id: 'q_3e_08', level: '3e', theme: 'Ve République', question: "En quelle année et comment de Gaulle fonde-t-il la Ve République ?", options: ["1944, par la Libération de Paris", "1958, par la Constitution du 4 octobre suite à la crise algérienne", "1962, par le référendum sur l'élection du président au suffrage universel", "1969, après les événements de Mai 68"], answer: "1958, par la Constitution du 4 octobre suite à la crise algérienne", explanation: "La crise algérienne et la menace de coup d'État militaire en mai 1958 ramènent de Gaulle au pouvoir. Il fait adopter une nouvelle Constitution (référendum du 28 septembre 1958, approuvée à 79%) qui établit la Ve République. Elle renforce le pouvoir exécutif (président de la République) au détriment du Parlement. En vigueur depuis lors.", difficulty: 2 },

  // ========== 2nde ==========
  { id: 'q_2nde_01', level: '2nde', theme: 'Méditerranée antique', question: "Qu'est-ce que l'hellénisme et quelle est son importance historique ?", options: ["La religion de la Grèce antique uniquement", "La diffusion de la culture grecque dans tout le Proche-Orient après les conquêtes d'Alexandre", "La langue grecque moderne", "Le mouvement artistique de la Renaissance"], answer: "La diffusion de la culture grecque dans tout le Proche-Orient après les conquêtes d'Alexandre", explanation: "L'hellénisme désigne la période et le phénomène culturel qui suit les conquêtes d'Alexandre le Grand (-336 à -323). La culture grecque (langue, art, philosophie) se diffuse dans tout le Proche-Orient et fusionne avec les cultures locales (égyptienne, perse, mésopotamienne). Elle crée une civilisation syncrétique qui dure jusqu'à la conquête romaine.", difficulty: 2 },
  { id: 'q_2nde_02', level: '2nde', theme: 'Sociétés médiévales', question: "Qu'est-ce que la ville médiévale représente par rapport au système féodal ?", options: ["La ville est soumise au seigneur local", "La ville représente un espace de liberté relative : les bourgeois obtiennent des franchises (charte communale) et s'émancipent de la féodalité", "La ville n'existe pas au Moyen Âge", "La ville est exclusivement un lieu de commerce sans vie politique"], answer: "La ville représente un espace de liberté relative : les bourgeois obtiennent des franchises (charte communale) et s'émancipent de la féodalité", explanation: "Les villes médiévales (bourgs) obtiennent progressivement des chartes communales qui leur accordent une autonomie. 'L'air de la ville rend libre' (Stadtluft macht frei) : le serf qui réside un an et un jour en ville est affranchi. Les bourgeois (habitants du bourg) constituent une classe sociale nouvelle, entre nobles et paysans.", difficulty: 3 },
  { id: 'q_2nde_03', level: '2nde', theme: 'XVIIIe siècle', question: "Qu'est-ce que le contrat social selon Rousseau ?", options: ["Un contrat entre le roi et les nobles", "Un accord par lequel les individus aliènent leur liberté naturelle à la communauté pour obtenir la liberté civile et la sécurité", "Un traité commercial entre nations", "Un accord entre l'Église et l'État"], answer: "Un accord par lequel les individus aliènent leur liberté naturelle à la communauté pour obtenir la liberté civile et la sécurité", explanation: "Dans Du Contrat Social (1762), Rousseau développe sa théorie : les hommes à l'état de nature sont libres et égaux. Pour vivre en société, ils concluent un contrat : ils renoncent à leur liberté naturelle absolue mais obtiennent la liberté civile (définie et protégée par les lois) et la sécurité. La souveraineté appartient au peuple (volonté générale).", difficulty: 3 },
  { id: 'q_2nde_04', level: '2nde', theme: 'Ouverture atlantique', question: "Qu'est-ce que le 'commerce triangulaire' ?", options: ["Le commerce entre Europe, Inde et Chine via les épices", "Un système d'échanges entre Europe, Afrique (esclaves) et Amériques (produits tropicaux)", "Le commerce méditerranéen entre France, Italie et Espagne", "Les échanges entre les 3 ordres de la société française"], answer: "Un système d'échanges entre Europe, Afrique (esclaves) et Amériques (produits tropicaux)", explanation: "Le commerce triangulaire est le système commercial qui lie l'Europe, l'Afrique et les Amériques du XVIe au XIXe siècle : les navires européens exportent des marchandises (armes, alcool, tissus) vers l'Afrique contre des esclaves ; les esclaves sont transportés en Amérique (Middle Passage, 2 millions de morts) ; les bateaux reviennent chargés de produits coloniaux (sucre, café, tabac).", difficulty: 2 },

  // ========== 1ère ==========
  { id: 'q_1e_01', level: '1ere', theme: 'Crises des années 30', question: "Pourquoi la crise de 1929 favorise-t-elle la montée des totalitarismes ?", options: ["Parce qu'elle enrichit les classes ouvrières", "Parce qu'elle plonge des millions de personnes dans la misère, nourrissant la colère contre les démocraties libérales au profit des partis extrémistes", "Parce qu'elle renforce les démocraties en Europe", "Parce qu'elle provoque une guerre entre les USA et l'URSS"], answer: "Parce qu'elle plonge des millions de personnes dans la misère, nourrissant la colère contre les démocraties libérales au profit des partis extrémistes", explanation: "La crise de 1929 touche l'Allemagne de plein fouet (6 millions de chômeurs en 1932). Le désespoir économique, la rancœur liée au traité de Versailles et la faiblesse de la République de Weimar permettent la montée en puissance du NSDAP. Hitler utilise la crise pour promettre travail, grandeur nationale et bouc émissaire (les Juifs).", difficulty: 2 },
  { id: 'q_1e_02', level: '1ere', theme: 'Régimes totalitaires', question: "Quelles sont les caractéristiques communes aux régimes totalitaires (nazisme, stalinisme) ?", options: ["Pluralisme politique, économie de marché, liberté individuelle", "Parti unique, idéologie officielle obligatoire, culte du chef, terreur, police politique, propagande, contrôle de l'économie", "Suffrage universel, presse libre, droits de l'homme", "Alliance militaire et économique entre États"], answer: "Parti unique, idéologie officielle obligatoire, culte du chef, terreur, police politique, propagande, contrôle de l'économie", explanation: "Hannah Arendt (Les origines du totalitarisme, 1951) définit le totalitarisme par : parti unique, idéologie totale (nazisme, marxisme-léninisme), culte du chef (Führer, Staline), terreur organisée (Gestapo, NKVD), propagande omniprésente (Goebbels), contrôle de l'économie et de la société entière. Il se distingue de l'autoritarisme par cette ambition de contrôle total.", difficulty: 2 },
  { id: 'q_1e_03', level: '1ere', theme: 'Shoah', question: "Que désigne le terme de 'génocide' et en quoi la Shoah en est-elle le paradigme ?", options: ["Une guerre entre deux peuples", "L'extermination intentionnelle et systématique d'un groupe humain — la Shoah (6 millions de Juifs) en est l'exemple le plus documenté", "Une famine provoquée par une politique économique", "L'expulsion d'une population de son territoire"], answer: "L'extermination intentionnelle et systématique d'un groupe humain — la Shoah (6 millions de Juifs) en est l'exemple le plus documenté", explanation: "Le génocide (terme de Lemkin, 1944) est défini par la Convention ONU de 1948 comme 'les actes commis dans l'intention de détruire, en tout ou en partie, un groupe national, ethnique, racial ou religieux'. La Shoah (1941-1945) en est le paradigme : décision bureaucratique organisée (Wannsee), industrialisation du meurtre (chambres à gaz), extermination de 6 millions de Juifs et de millions d'autres victimes.", difficulty: 2 },
  { id: 'q_1e_04', level: '1ere', theme: 'France Libre', question: "Pourquoi l'Appel du 18 juin 1940 est-il historique ?", options: ["C'est le premier discours à la radio en France", "De Gaulle, depuis Londres, refuse la défaite et l'armistice, appelant les Français à continuer le combat — fondement de la France Libre", "C'est le discours de la capitulation de la France", "C'est l'annonce de la Résistance intérieure par Jean Moulin"], answer: "De Gaulle, depuis Londres, refuse la défaite et l'armistice, appelant les Français à continuer le combat — fondement de la France Libre", explanation: "Le 18 juin 1940, le général de Gaulle parle sur la BBC depuis Londres. Il refuse l'armistice signé la veille et affirme que la guerre n'est pas finie : la France a perdu une bataille, pas la guerre. Il appelle les militaires, ingénieurs et techniciens français à le rejoindre. Cet appel fonde la France Libre, mouvement de résistance extérieure. Il sera le fondement de la légitimité de De Gaulle.", difficulty: 1 },
  { id: 'q_1e_05', level: '1ere', theme: 'Décolonisation', question: "Quelles sont les deux voies principales de la décolonisation ?", options: ["Colonisation économique et colonisation militaire", "Voie négociée (comme le Maroc en 1956) et voie armée (comme l'Algérie 1954-1962)", "Décolonisation par vote à l'ONU et décolonisation par intervention américaine", "Décolonisation africaine et décolonisation asiatique"], answer: "Voie négociée (comme le Maroc en 1956) et voie armée (comme l'Algérie 1954-1962)", explanation: "La décolonisation prend deux formes : la voie pacifique (négociée), souvent après des pressions diplomatiques et des mouvements nationalistes — Maroc et Tunisie (1956), Afrique noire française (1960) ; la voie armée (guerre d'indépendance) — Indochine (1946-1954), Algérie (1954-1962), Angola, Mozambique, Zimbabwe. La violence de la colonisation explique souvent la violence de la décolonisation.", difficulty: 2 },
  { id: 'q_1e_06', level: '1ere', theme: 'Ve République', question: "Pourquoi la Constitution de 1958 crée-t-elle un régime 'semi-présidentiel' ?", options: ["Parce que le président est élu pour 2 ans et demi seulement", "Parce qu'elle combine un exécutif fort (président) et un gouvernement responsable devant le Parlement", "Parce que le Parlement peut dissoudre le gouvernement seul", "Parce que la France est une fédération"], answer: "Parce qu'elle combine un exécutif fort (président) et un gouvernement responsable devant le Parlement", explanation: "La Ve République est semi-présidentielle : le président dispose de pouvoirs étendus (nomme le Premier ministre, peut dissoudre l'Assemblée, recourt au référendum, article 16). Mais le gouvernement doit aussi disposer de la confiance du Parlement (régime parlementaire). Cette double responsabilité crée parfois la cohabitation (président et Premier ministre de camps opposés).", difficulty: 3 },

  // ========== Terminale ==========
  { id: 'q_term_01', level: 'Terminale', theme: 'USA et le monde', question: "Qu'est-ce que la doctrine Truman (1947) et comment change-t-elle la politique étrangère américaine ?", options: ["Elle proclame la neutralité des USA dans les affaires mondiales", "Elle engage les USA à soutenir tout peuple libre menacé par le communisme — abandonnant l'isolationnisme pour le containment", "Elle crée l'Alliance Atlantique (OTAN)", "Elle lance le réarmement américain après Pearl Harbor"], answer: "Elle engage les USA à soutenir tout peuple libre menacé par le communisme — abandonnant l'isolationnisme pour le containment", explanation: "La doctrine Truman (12 mars 1947) marque la fin de l'isolationnisme américain. Truman demande au Congrès 400 millions pour aider la Grèce et la Turquie menacées par le communisme. Il formule le principe : les USA doivent soutenir 'les peuples libres qui résistent à l'assujettissement par des minorités armées ou des pressions extérieures'. C'est le fondement du containment.", difficulty: 2 },
  { id: 'q_term_02', level: 'Terminale', theme: 'Chine', question: "Pourquoi les réformes de Deng Xiaoping (1978) sont-elles un tournant historique ?", options: ["Elles instaurent la démocratie en Chine", "Elles créent une 'économie socialiste de marché', lançant la croissance spectaculaire de la Chine tout en maintenant la dictature du Parti", "Elles ouvrent la Chine aux partis politiques d'opposition", "Elles abandonnent le communisme et adoptent le capitalisme libéral"], answer: "Elles créent une 'économie socialiste de marché', lançant la croissance spectaculaire de la Chine tout en maintenant la dictature du Parti", explanation: "Deng Xiaoping lance en 1978 les 'Quatre Modernisations' (agriculture, industrie, défense, sciences/technologie). Il crée des Zones Économiques Spéciales où le marché peut fonctionner. La formule : 'Peu importe que le chat soit noir ou blanc, pourvu qu'il attrape les souris'. Résultat : la Chine devient la 2e économie mondiale tout en maintenant la dictature du Parti communiste.", difficulty: 2 },
  { id: 'q_term_03', level: 'Terminale', theme: 'Mondialisation', question: "Qu'est-ce que la 'malédiction des ressources' ?", options: ["L'épuisement progressif des ressources naturelles mondiales", "Le paradoxe par lequel les pays richement dotés en ressources naturelles connaissent souvent sous-développement et instabilité politique", "La pollution générée par l'exploitation des ressources", "La dépendance des pays pauvres vis-à-vis des matières premières"], answer: "Le paradoxe par lequel les pays richement dotés en ressources naturelles connaissent souvent sous-développement et instabilité politique", explanation: "La 'malédiction des ressources' ou 'paradoxe de l'abondance' désigne le fait que les États très riches en pétrole ou minerais (Nigeria, Venezuela, RDC) connaissent paradoxalement corruption généralisée, guerres civiles, autoritarisme et retard de développement. Les revenus des ressources financent les conflits et enrichissent les élites plutôt que de développer l'économie.", difficulty: 3 },

  // ========== HGGSP ==========
  { id: 'q_hggsp_01', level: 'HGGSP', theme: 'Démocratie', question: "Qu'est-ce que la 'récession démocratique' observée depuis 2006 par Freedom House ?", options: ["Une diminution du nombre de partis politiques dans les démocraties", "Un recul mondial du nombre de démocraties libérales et des libertés, au profit des régimes autoritaires et des démocraties illibérales", "La baisse de la participation électorale dans les démocraties occidentales uniquement", "La fin de la démocratie représentative au profit de la démocratie directe"], answer: "Un recul mondial du nombre de démocraties libérales et des libertés, au profit des régimes autoritaires et des démocraties illibérales", explanation: "Freedom House (ONG américaine) mesure chaque année l'état des libertés dans le monde. Depuis 2006, elle observe 15 années consécutives de recul des libertés mondiales (en 2021). Des démocraties régressent (Hongrie, Turquie, Brésil sous Bolsonaro) et des régimes autoritaires se consolident (Chine, Russie, Belarus). C'est la 'troisième vague de démocratisation' en recul.", difficulty: 3 },
  { id: 'q_hggsp_02', level: 'HGGSP', theme: 'Guerre et paix', question: "Pourquoi les guerres asymétriques sont-elles difficiles à gagner pour le plus fort militairement ?", options: ["Parce que les armes modernes sont inefficaces contre les guérillas", "Parce que le plus fort militairement peut gagner les batailles mais perdre politiquement la guerre (légitimité, opinion publique, enlisement)", "Parce que la guérilla dispose toujours d'armes supérieures", "Parce que les guerres asymétriques se terminent toujours par une négociation"], answer: "Parce que le plus fort militairement peut gagner les batailles mais perdre politiquement la guerre (légitimité, opinion publique, enlisement)", explanation: "Dans une guerre asymétrique, le plus faible militairement utilise des méthodes non-conventionnelles (guérilla, terrorisme, piège à l'opinion publique). Le Vietnam montre que les USA, supérieurs militairement, ont perdu politiquement face au Viêt-Cong. L'Afghanistan (1979-1989 contre l'URSS, 2001-2021 contre les USA) illustre le même phénomène : l'occupant ne peut pas 'tenir' un pays hostile.", difficulty: 3 },
  { id: 'q_hggsp_03', level: 'HGGSP', theme: 'Ressources', question: "Pourquoi les terres rares constituent-elles un enjeu géopolitique au XXIe siècle ?", options: ["Parce qu'elles sont radioactives et dangereuses", "Parce qu'elles sont indispensables aux technologies vertes et numériques et que la Chine en contrôle 60-70% de la production", "Parce que leur exploitation détruit les forêts tropicales", "Parce qu'elles ne se trouvent qu'en Antarctique"], answer: "Parce qu'elles sont indispensables aux technologies vertes et numériques et que la Chine en contrôle 60-70% de la production", explanation: "Les terres rares (17 éléments dont néodyme, dysprosium, lithium, cobalt) sont indispensables pour les batteries des véhicules électriques, les éoliennes, les smartphones, les missiles guidés. La Chine contrôle 60-70% de la production mondiale et 85% du raffinage. En 2010, elle a utilisé cette position comme arme géopolitique contre le Japon (embargo). Cela explique la course mondiale à ces ressources.", difficulty: 3 },
  { id: 'q_hggsp_04', level: 'HGGSP', theme: 'Puissances', question: "Comment définir le 'smart power' selon Joseph Nye ?", options: ["La puissance nucléaire d'un État", "La combinaison intelligente de hard power (contrainte) et de soft power (attraction) selon les situations", "La capacité technologique d'un pays en matière de numérique", "La puissance économique uniquement"], answer: "La combinaison intelligente de hard power (contrainte) et de soft power (attraction) selon les situations", explanation: "Joseph Nye (Smart Power, 2004) propose le concept de 'smart power' : la combinaison optimale de hard power (capacité militaire et économique de contraindre) et de soft power (attraction culturelle, normative, diplomatique). Les USA sous Obama (2009-2017) ont essayé de pratiquer le smart power : dialogue diplomatique + maintien de la puissance militaire. La capacité à choisir le bon outil dans chaque situation.", difficulty: 3 },

  // ========== 4ème (nouvelles questions) ==========
  { id: 'q_4e_08', level: '4e', theme: 'Terreur', question: "Qui est Robespierre et quel rôle joue-t-il pendant la Terreur (1793-1794) ?", options: ["Un général qui conquiert l'Égypte", "Un modéré qui protège les girondins", "Le principal dirigeant du Comité de Salut Public qui organise la Terreur pour sauver la République", "Le roi Louis XVI"], answer: "Le principal dirigeant du Comité de Salut Public qui organise la Terreur pour sauver la République", explanation: "Maximilien de Robespierre (1758-1794) est le principal dirigeant du Comité de Salut Public. Il justifie la Terreur (guillotine, tribunaux révolutionnaires) par la nécessité de défendre la République contre ses ennemis intérieurs et extérieurs. Près de 17 000 personnes sont guillotinées entre 1793 et 1794. Il est lui-même arrêté et guillotiné le 9 Thermidor an II (27 juillet 1794).", difficulty: 2, points: 10 },
  { id: 'q_4e_09', level: '4e', theme: 'Terreur', question: "Que se passe-t-il le 9 Thermidor an II (27 juillet 1794) ?", options: ["La prise de la Bastille", "Le début de la Terreur sous Robespierre", "Robespierre est renversé et guillotiné — fin de la Terreur", "Napoléon prend le pouvoir"], answer: "Robespierre est renversé et guillotiné — fin de la Terreur", explanation: "Le 9 Thermidor an II (27 juillet 1794), des membres de la Convention (Tallien, Fouché, Barras) renversent Robespierre lors d'un coup de force. Robespierre et ses alliés (Saint-Just, Couthon) sont arrêtés et guillotinés le lendemain. Ce coup de Thermidor met fin à la Grande Terreur. Il marque le début de la réaction thermidorienne et l'affaiblissement de la Révolution radicale.", difficulty: 2, points: 10 },
  { id: 'q_4e_10', level: '4e', theme: 'Empire', question: "Quand et comment Napoléon se sacre-t-il Empereur ?", options: ["1799, lors du coup d'État du 18 Brumaire", "1804, il se couronne lui-même Empereur à Notre-Dame de Paris en présence du pape Pie VII", "1805, après la victoire d'Austerlitz", "1815, après son retour de l'île d'Elbe"], answer: "1804, il se couronne lui-même Empereur à Notre-Dame de Paris en présence du pape Pie VII", explanation: "Le 2 décembre 1804, Napoléon Bonaparte est sacré Empereur des Français à Notre-Dame de Paris. Le pape Pie VII est présent mais, selon la légende (immortalisée par le tableau de David), Napoléon prend lui-même la couronne des mains du pape pour se couronner, affirmant qu'il ne tient son pouvoir que de lui-même et de la Nation, non de l'Église.", difficulty: 1, points: 10 },
  { id: 'q_4e_11', level: '4e', theme: 'Empire', question: "Pourquoi la bataille d'Austerlitz (2 décembre 1805) est-elle le chef-d'oeuvre militaire de Napoléon ?", options: ["C'est la première victoire de Napoléon", "Napoléon y bat simultanément les armées autrichienne et russe en les piégeant par une feinte brillante", "C'est la victoire qui met fin aux guerres napoléoniennes", "Napoléon y détruit la flotte anglaise"], answer: "Napoléon y bat simultanément les armées autrichienne et russe en les piégeant par une feinte brillante", explanation: "À Austerlitz (Moravie, 2 décembre 1805), Napoléon bat l'armée austro-russe de l'Empereur François II et du Tsar Alexandre Ier. Il feint de laisser son aile droite faible pour attirer l'ennemi, puis enfonce le centre allié au plateau de Pratzen. 11 000 morts alliés contre 1 500 Français. C'est considéré comme son plus grand succès tactique et le symbole du génie napoléonien.", difficulty: 2, points: 10 },
  { id: 'q_4e_12', level: '4e', theme: 'Empire', question: "Quelle est la principale raison de la chute de Napoléon ?", options: ["Une trahison de ses maréchaux dès 1805", "La défaite navale de Trafalgar uniquement", "L'épuisement de la France après 20 ans de guerres, la désastreuse campagne de Russie (1812) et la coalition européenne", "L'opposition du pape Pie VII"], answer: "L'épuisement de la France après 20 ans de guerres, la désastreuse campagne de Russie (1812) et la coalition européenne", explanation: "La chute de Napoléon résulte de plusieurs facteurs : la désastreuse campagne de Russie (1812 : la Grande Armée de 600 000 hommes rentre à 100 000), la résistance nationale espagnole (guerre d'Espagne 1808-1814), l'épuisement humain et économique de la France, et la coalition des puissances européennes. Waterloo (18 juin 1815) est la défaite finale.", difficulty: 2, points: 10 },
  { id: 'q_4e_13', level: '4e', theme: 'Traite des esclaves', question: "Qu'est-ce que le Middle Passage dans la traite atlantique ?", options: ["La route commerciale entre l'Europe et les Indes", "La traversée de l'Atlantique par les navires négriers transportant des esclaves africains vers les Amériques", "Le passage des esclaves du marché vers les plantations", "Le canal reliant l'Atlantique au Pacifique"], answer: "La traversée de l'Atlantique par les navires négriers transportant des esclaves africains vers les Amériques", explanation: "Le Middle Passage (passage du milieu) désigne la deuxième partie du commerce triangulaire : la traversée de l'Atlantique par les navires négriers transportant les esclaves africains vers les Amériques. Les conditions étaient effroyables : entassés dans les cales, les esclaves manquaient d'air, d'eau et de nourriture. Environ 2 millions de personnes moururent durant cette traversée sur les ~12 millions déportés.", difficulty: 2, points: 10 },
  { id: 'q_4e_14', level: '4e', theme: 'Traite des esclaves', question: "Quel est le rôle de Victor Schoelcher dans l'abolition de l'esclavage ?", options: ["Il fonde la première colonie française en Afrique", "Il rédige le décret d'abolition de l'esclavage dans les colonies françaises (27 avril 1848)", "Il dirige la révolte des esclaves en Haïti", "Il est le premier président noir des Antilles françaises"], answer: "Il rédige le décret d'abolition de l'esclavage dans les colonies françaises (27 avril 1848)", explanation: "Victor Schoelcher (1804-1893) est le sous-secrétaire d'État aux Colonies de la IIe République. Il rédige le décret du 27 avril 1848 abolissant définitivement l'esclavage dans toutes les colonies françaises. C'est la deuxième abolition française (la première, en 1794, avait été annulée par Napoléon en 1802). Schoelcher est une figure majeure de la lutte abolitionniste en France.", difficulty: 2, points: 10 },
  { id: 'q_4e_15', level: '4e', theme: '1848', question: "Qu'est-ce que le coup d'État du 2 décembre 1851 de Louis-Napoléon Bonaparte ?", options: ["Le renversement de la monarchie de Juillet", "La proclamation de la IIe République", "Le renversement par la force de l'Assemblée nationale par Louis-Napoléon, qui deviendra Napoléon III", "La révolution de février 1848"], answer: "Le renversement par la force de l'Assemblée nationale par Louis-Napoléon, qui deviendra Napoléon III", explanation: "Louis-Napoléon Bonaparte, élu président de la IIe République en décembre 1848, ne peut être réélu. Le 2 décembre 1851 (anniversaire d'Austerlitz), il renverse l'Assemblée nationale par un coup d'État militaire. Après un plébiscite, il se proclame Napoléon III et fonde le Second Empire (1852-1870). Le coup d'État est réprimé dans le sang : 400 morts à Paris, 10 000 déportés en Algérie.", difficulty: 2, points: 10 },

  // ========== 3ème (nouvelles questions) ==========
  { id: 'q_3e_09', level: '3e', theme: 'Nazisme', question: "Que sont les lois de Nuremberg (septembre 1935) ?", options: ["Les lois fondant la République de Weimar", "Les lois nazies qui privent les Juifs de la citoyenneté allemande et interdisent les mariages mixtes", "Les lois du tribunal de Nuremberg jugeant les criminels nazis", "Les lois économiques du IIIe Reich"], answer: "Les lois nazies qui privent les Juifs de la citoyenneté allemande et interdisent les mariages mixtes", explanation: "Adoptées lors du congrès du parti nazi à Nuremberg en septembre 1935, ces lois excluent officiellement les Juifs de la communauté nationale allemande : ils perdent la citoyenneté, ne peuvent pas se marier avec des non-Juifs, ne peuvent pas employer de domestiques allemands. Elles formalisent légalement l'antisémitisme nazi et préparent les persécutions ultérieures.", difficulty: 2, points: 10 },
  { id: 'q_3e_10', level: '3e', theme: 'Nazisme', question: "Comment Hitler prend-il légalement le pouvoir en Allemagne en 1933 ?", options: ["Par un coup d'État militaire en 1933", "Il est nommé chancelier par le président Hindenburg le 30 janvier 1933 après les succès électoraux du NSDAP", "Par un putsch comme à Munich en 1923", "Par référendum direct après la mort de Hindenburg"], answer: "Il est nommé chancelier par le président Hindenburg le 30 janvier 1933 après les succès électoraux du NSDAP", explanation: "Hitler n'accède pas au pouvoir par un coup de force mais par une voie légale : le NSDAP obtient 37% des voix en juillet 1932. Face à la crise, le président Hindenburg nomme Hitler chancelier le 30 janvier 1933, croyant pouvoir le contrôler. Hitler profite de l'incendie du Reichstag (27 février 1933) pour décréter l'état d'urgence et éliminer ses opposants. En août 1934, après la mort de Hindenburg, il concentre tous les pouvoirs.", difficulty: 2, points: 10 },
  { id: 'q_3e_11', level: '3e', theme: 'Nazisme', question: "Pourquoi la République de Weimar (1919-1933) était-elle fragile ?", options: ["Parce qu'elle était trop autoritaire", "Parce qu'elle était soutenue par tous les partis politiques allemands", "Parce qu'elle subissait l'hyperinflation (1923), la crise de 1929, la polarisation entre extrêmes et le poids de Versailles", "Parce qu'elle n'avait pas de constitution"], answer: "Parce qu'elle subissait l'hyperinflation (1923), la crise de 1929, la polarisation entre extrêmes et le poids de Versailles", explanation: "La République de Weimar (1919-1933), première démocratie allemande, est fragilisée dès sa naissance : née de la défaite de 1918 et du traité de Versailles qu'elle est forcée de signer, elle subit l'hyperinflation de 1923 (1 dollar = 4 200 milliards de marks), la Grande Dépression de 1929 (6 millions de chômeurs), la polarisation entre KPD (communistes) et NSDAP (nazis). Elle s'effondre quand Hitler est nommé chancelier en 1933.", difficulty: 2, points: 10 },
  { id: 'q_3e_12', level: '3e', theme: '2GM', question: "Qu'est-ce que le Blitzkrieg ('guerre éclair') pratiqué par l'Allemagne nazie ?", options: ["La guerre sous-marine allemande dans l'Atlantique", "Une stratégie combinant chars, avions et infanterie motorisée pour enfoncer rapidement les défenses adverses", "Les bombardements de Londres par la Luftwaffe", "La stratégie de défense de la ligne Maginot"], answer: "Une stratégie combinant chars, avions et infanterie motorisée pour enfoncer rapidement les défenses adverses", explanation: "Le Blitzkrieg (guerre éclair) est la doctrine militaire allemande fondée sur la vitesse et la surprise : les Panzer (chars) percent les lignes adverses, l'aviation (Stukas) bombarde l'arrière, l'infanterie motorisée suit rapidement. Cette stratégie permit la chute de la France en 6 semaines (mai-juin 1940), de la Pologne en 3 semaines (septembre 1939) et de la Yougoslavie en 11 jours (avril 1941).", difficulty: 1, points: 10 },
  { id: 'q_3e_13', level: '3e', theme: '2GM', question: "Pourquoi la bataille de Stalingrad (1942-1943) est-elle un tournant de la Seconde Guerre mondiale ?", options: ["C'est la première victoire alliée dans le Pacifique", "La défaite et la reddition de la 6e armée allemande (300 000 hommes) marquent le début du recul allemand sur le front Est", "C'est la bataille où les Américains débarquent en Europe", "C'est la bataille qui permet à l'URSS de rejoindre les Alliés"], answer: "La défaite et la reddition de la 6e armée allemande (300 000 hommes) marquent le début du recul allemand sur le front Est", explanation: "La bataille de Stalingrad (août 1942 - 2 février 1943) est le tournant de la guerre à l'Est. La 6e armée du maréchal Paulus, encerclée par les Soviétiques, se rend avec 300 000 hommes (dont 91 000 prisonniers). C'est la première grande défaite allemande. Elle brise le mythe de l'invincibilité de la Wehrmacht et marque le début de la contre-offensive soviétique qui mènera à Berlin.", difficulty: 2, points: 10 },
  { id: 'q_3e_14', level: '3e', theme: '2GM', question: "Que se passe-t-il lors du Débarquement en Normandie (6 juin 1944) ?", options: ["Les Soviétiques débarquent en Pologne", "Les forces alliées (USA, UK, Canada) ouvrent un second front en France pour libérer l'Europe de l'Ouest", "Les Alliés débarquent en Italie pour la première fois", "Hitler déclare la capitulation de l'Allemagne"], answer: "Les forces alliées (USA, UK, Canada) ouvrent un second front en France pour libérer l'Europe de l'Ouest", explanation: "L'opération Overlord (6 juin 1944) est la plus grande opération amphibie de l'Histoire : 156 000 soldats alliés débarquent sur 5 plages de Normandie (Utah, Omaha, Gold, Juno, Sword). Commandée par Eisenhower, l'opération ouvre enfin le second front à l'Ouest. La bataille de Normandie dure jusqu'en août 1944. Paris est libéré le 25 août 1944.", difficulty: 1, points: 10 },
  { id: 'q_3e_15', level: '3e', theme: 'Vichy', question: "Combien de parlementaires votent pour les pleins pouvoirs à Pétain le 10 juillet 1940 ?", options: ["569 pour, 80 contre", "200 pour, 400 contre", "700 pour, 0 contre", "400 pour, 200 contre"], answer: "569 pour, 80 contre", explanation: "Le 10 juillet 1940 à Vichy, 569 parlementaires votent pour donner les pleins pouvoirs au maréchal Pétain (seul 80 votent contre — les 80 du refus). Ce vote légal met fin à la IIIe République. L'acte constitutionnel n°1 concentre tous les pouvoirs entre les mains de Pétain. La France démocratique s'est suicide par son propre Parlement.", difficulty: 2, points: 10 },
  { id: 'q_3e_16', level: '3e', theme: 'Vichy', question: "Quel est le bilan de la rafle du Vél d'Hiv (juillet 1942) ?", options: ["500 Juifs arrêtés, tous libérés ensuite", "13 152 Juifs arrêtés (dont 4 000 enfants), déportés vers Auschwitz — 811 survivants", "1 000 Juifs étrangers uniquement arrêtés", "Uniquement des adultes sans enfants arrêtés"], answer: "13 152 Juifs arrêtés (dont 4 000 enfants), déportés vers Auschwitz — 811 survivants", explanation: "La rafle du Vélodrome d'Hiver (16-17 juillet 1942) aboutit à l'arrestation de 13 152 personnes (dont 4 115 enfants). Regroupés dans des conditions inhumaines au Vel d'Hiv (sans eau, sans nourriture, en pleine chaleur estivale), ils sont ensuite transférés dans des camps de transit (Drancy, Pithiviers) puis déportés vers Auschwitz-Birkenau. Seulement 811 survivront.", difficulty: 2, points: 10 },
  { id: 'q_3e_17', level: '3e', theme: 'Shoah', question: "Qu'est-ce que la conférence de Wannsee (20 janvier 1942) ?", options: ["Une réunion des résistants contre Hitler", "La réunion de 15 hauts fonctionnaires nazis planifiant la 'solution finale' — l'extermination de tous les Juifs d'Europe", "Un accord de paix entre l'Allemagne et l'URSS", "La réunion fondatrice des SS"], answer: "La réunion de 15 hauts fonctionnaires nazis planifiant la 'solution finale' — l'extermination de tous les Juifs d'Europe", explanation: "Le 20 janvier 1942, 15 hauts fonctionnaires nazis se réunissent dans une villa au bord du lac Wannsee (Berlin) présidés par Reinhard Heydrich. En 90 minutes, ils planifient la 'solution finale à la question juive' : déportation systématique et extermination de tous les Juifs d'Europe dans des camps spécialement construits (Auschwitz-Birkenau, Treblinka, Sobibor, Belzec, Chelmno, Majdanek).", difficulty: 2, points: 10 },
  { id: 'q_3e_18', level: '3e', theme: 'Shoah', question: "Qu'est-ce qu'un génocide selon la définition de l'ONU (1948) ?", options: ["Un massacre de soldats au cours d'une bataille", "Une famine provoquée par une politique économique", "Des actes commis dans l'intention de détruire, en tout ou en partie, un groupe national, ethnique, racial ou religieux", "L'expulsion forcée d'une population de son territoire"], answer: "Des actes commis dans l'intention de détruire, en tout ou en partie, un groupe national, ethnique, racial ou religieux", explanation: "La Convention pour la prévention et la répression du crime de génocide (ONU, 9 décembre 1948) définit le génocide comme des actes (meurtres, atteintes graves, conditions d'existence destructrices, entraves aux naissances, transferts d'enfants) commis avec l'intention de détruire en tout ou partie un groupe national, ethnique, racial ou religieux. La Shoah, le génocide des Arméniens (1915) et le génocide des Tutsi au Rwanda (1994) en sont des exemples.", difficulty: 2, points: 10 },

  // ========== 2nde (nouvelles questions) ==========
  { id: 'q_2nde_05', level: '2nde', theme: 'Renaissance', question: "Quel est l'impact de l'imprimerie de Gutenberg (~1450) sur la société européenne ?", options: ["Elle n'a d'impact que dans les monastères", "Elle révolutionne la diffusion des idées : les livres sont 10 fois moins chers, permettant la diffusion de la Renaissance et de la Réforme", "Elle remplace les peintres dans la reproduction des oeuvres d'art", "Elle est réservée aux seuls savants universitaires"], answer: "Elle révolutionne la diffusion des idées : les livres sont 10 fois moins chers, permettant la diffusion de la Renaissance et de la Réforme", explanation: "L'imprimerie à caractères mobiles de Gutenberg (~1450) est l'une des inventions les plus révolutionnaires de l'Histoire. Elle réduit le coût des livres d'un facteur 10, permettant leur diffusion massive. En 50 ans, 12 millions de livres sont imprimés contre quelques milliers de manuscrits copiés à la main. Elle est le vecteur essentiel de la Renaissance humaniste et de la Réforme protestante (Luther diffuse ses idées grâce à l'imprimerie).", difficulty: 2, points: 10 },
  { id: 'q_2nde_06', level: '2nde', theme: 'Renaissance', question: "Pourquoi Léonard de Vinci est-il le symbole de l'idéal humaniste de la Renaissance ?", options: ["Parce qu'il est le seul artiste de la Renaissance", "Parce qu'il incarne l'homme universel : peintre, sculpteur, architecte, ingénieur et scientifique à la fois", "Parce qu'il est le pape de la Renaissance", "Parce qu'il traduit la Bible en italien"], answer: "Parce qu'il incarne l'homme universel : peintre, sculpteur, architecte, ingénieur et scientifique à la fois", explanation: "Léonard de Vinci (1452-1519) incarne l'idéal humaniste de l'homo universalis : il est à la fois peintre (La Joconde, La Cène), sculpteur, architecte, ingénieur militaire (machines de guerre, fossés), inventeur (hélicoptère, char d'assaut dans ses carnets), anatomiste et géologue. Il symbolise l'idée que l'homme de la Renaissance peut maîtriser toutes les disciplines grâce à la raison et à l'observation.", difficulty: 1, points: 10 },
  { id: 'q_2nde_07', level: '2nde', theme: 'Renaissance', question: "Quelle est la théorie de Copernic (1543) et pourquoi est-elle révolutionnaire ?", options: ["La Terre est plate", "La Terre tourne autour du Soleil (héliocentrisme), renversant 1500 ans de géocentrisme ptoléméen", "Le Soleil tourne autour de la Terre", "La Lune est une planète comme les autres"], answer: "La Terre tourne autour du Soleil (héliocentrisme), renversant 1500 ans de géocentrisme ptoléméen", explanation: "Nicolas Copernic (De revolutionibus orbium coelestium, 1543) affirme que le Soleil est au centre du système solaire et que la Terre tourne autour de lui (héliocentrisme). C'est une révolution car cela contredit l'Église (qui place l'homme et la Terre au centre de la création selon Ptolémée) et 1500 ans de tradition scientifique. Galilée confirmera cette théorie (1610) et sera condamné par l'Inquisition (1633).", difficulty: 2, points: 10 },
  { id: 'q_2nde_08', level: '2nde', theme: 'Réforme', question: "Que remet en cause Luther dans ses 95 Thèses affichées à Wittenberg le 31 octobre 1517 ?", options: ["L'existence de Dieu", "La vente des indulgences et la toute-puissance du pape, au profit de la foi seule (sola fide)", "Le pouvoir temporel des rois chrétiens", "La langue latine dans la liturgie uniquement"], answer: "La vente des indulgences et la toute-puissance du pape, au profit de la foi seule (sola fide)", explanation: "Luther remet en cause principalement la vente des indulgences (certificats censés réduire le séjour au purgatoire contre de l'argent). Il affirme que le salut vient de la foi seule (sola fide), non des oeuvres ou des achats, et que l'Écriture sainte est la seule autorité (sola scriptura), non le pape. Ces thèses, diffusées grâce à l'imprimerie, déclenchent la Réforme protestante et la division permanente du christianisme européen.", difficulty: 2, points: 10 },
  { id: 'q_2nde_09', level: '2nde', theme: 'Réforme', question: "Combien de personnes sont massacrées lors de la Saint-Barthélemy (24 août 1572) ?", options: ["Quelques dizaines dans une seule ville", "Environ 3 000 protestants à Paris en une nuit, et peut-être 10 000 à 30 000 en France", "Seulement des chefs militaires protestants ciblés", "Plus d'un million de personnes dans toute l'Europe"], answer: "Environ 3 000 protestants à Paris en une nuit, et peut-être 10 000 à 30 000 en France", explanation: "Dans la nuit du 23 au 24 août 1572, au signal de la cloche du palais royal, des catholiques massacrent les protestants (huguenots) réunis à Paris pour le mariage d'Henri de Navarre. Environ 3 000 morts à Paris en une nuit. Les massacres s'étendent en province : 10 000 à 30 000 morts au total en France. Cet événement traumatique reste un symbole des guerres de Religion et de l'intolérance religieuse.", difficulty: 2, points: 10 },
  { id: 'q_2nde_10', level: '2nde', theme: "Ancien Régime", question: "Quels sont les 3 ordres de la société française d'Ancien Régime et leur proportion dans la population ?", options: ["Roi, Nobles, Bourgeois — à peu près en nombre égal", "Clergé (1%), Noblesse (2%), Tiers-État (97%) — inégalité juridique et fiscale fondamentale", "Seigneurs, Paysans, Marchands", "Catholiques, Protestants, Athées"], answer: "Clergé (1%), Noblesse (2%), Tiers-État (97%) — inégalité juridique et fiscale fondamentale", explanation: "La société d'Ancien Régime est divisée en 3 ordres aux droits très inégaux : 1er ordre = Clergé (~100 000 personnes, exemptés des impôts, percevant la dîme) ; 2e ordre = Noblesse (~400 000, exemptés de la taille) ; 3e ordre = Tiers-État (~28 millions = 97%, payent tous les impôts). Cette inégalité fiscale criante, combinée aux idées des Lumières, est l'un des moteurs de la Révolution de 1789.", difficulty: 1, points: 10 },

  // ========== 1ère (nouvelles questions) ==========
  { id: 'q_1e_07', level: '1ere', theme: 'Première Guerre mondiale', question: "Quel événement déclenche la Première Guerre mondiale le 28 juin 1914 ?", options: ["L'invasion de la Belgique par l'Allemagne", "L'assassinat de l'archiduc François-Ferdinand à Sarajevo par Gavrilo Princip", "La mobilisation générale de la Russie", "La déclaration de guerre de la France à l'Allemagne"], answer: "L'assassinat de l'archiduc François-Ferdinand à Sarajevo par Gavrilo Princip", explanation: "Le 28 juin 1914, l'archiduc François-Ferdinand, héritier de l'empire austro-hongrois, est assassiné à Sarajevo par Gavrilo Princip, membre de la Jeune-Bosnie (mouvement nationaliste serbe). Cet attentat déclenche le mécanisme des alliances : ultimatum austro-hongrois à la Serbie, mobilisation russe, déclaration de guerre allemande à la Russie puis à la France, entrée en guerre du Royaume-Uni. La guerre générale commence en août 1914.", difficulty: 1, points: 10 },
  { id: 'q_1e_08', level: '1ere', theme: 'Première Guerre mondiale', question: "Pourquoi parle-t-on de 'guerre des tranchées' pour décrire la 1GM ?", options: ["Parce que les soldats utilisaient des tranchées comme armes offensives", "Parce que le front s'est stabilisé dès l'automne 1914 : les soldats vivent dans des réseaux de tranchées et les assauts gagnent peu de terrain au prix de pertes immenses", "Parce que les tranchées remplacent la cavalerie", "Parce que les tranchées permettent aux soldats de fuir les combats"], answer: "Parce que le front s'est stabilisé dès l'automne 1914 : les soldats vivent dans des réseaux de tranchées et les assauts gagnent peu de terrain au prix de pertes immenses", explanation: "Après l'échec du plan Schlieffen, le front occidental se stabilise dès l'automne 1914 sur 700 km de la Mer du Nord aux Alpes. Les soldats creusent des réseaux de tranchées (souvent dans la boue, l'eau et les rats). Les assauts pour percer les lignes adverses coûtent des centaines de milliers de vies pour gagner quelques kilomètres (Verdun : 700 000 morts en 6 mois ; Somme : 1 million de morts). La guerre de tranchées dure jusqu'en 1918.", difficulty: 1, points: 10 },
  { id: 'q_1e_09', level: '1ere', theme: 'Première Guerre mondiale', question: "Quelles sont les principales clauses imposées à l'Allemagne par le traité de Versailles (1919) ?", options: ["L'Allemagne reçoit des réparations pour ses pertes", "Clause de culpabilité (art. 231), réparations de 132 milliards de marks, pertes territoriales, désarmement", "L'Allemagne est simplement priée de réduire son armée", "Le traité est négocié équitablement entre toutes les parties"], answer: "Clause de culpabilité (art. 231), réparations de 132 milliards de marks, pertes territoriales, désarmement", explanation: "Le traité de Versailles (28 juin 1919) impose à l'Allemagne : 1) L'article 231 (clause de culpabilité) qui déclare l'Allemagne seule responsable de la guerre ; 2) Des réparations de 132 milliards de marks-or ; 3) Des pertes territoriales (Alsace-Lorraine à la France, Eupen-Malmedy à la Belgique, Posnanie à la Pologne) ; 4) Le désarmement (armée limitée à 100 000 hommes). Cette humiliation est le principal carburant du nationalisme allemand et du nazisme.", difficulty: 2, points: 10 },
  { id: 'q_1e_10', level: '1ere', theme: 'Première Guerre mondiale', question: "Comment la Première Guerre mondiale se termine-t-elle et quand ?", options: ["Par la capitulation de la France le 11 novembre 1918", "Par l'armistice du 11 novembre 1918, signé dans un wagon à Rethondes — fin des combats sur le front occidental", "Par la victoire de l'Allemagne sur la Russie", "Par une paix négociée à Paris le 14 juillet 1919"], answer: "Par l'armistice du 11 novembre 1918, signé dans un wagon à Rethondes — fin des combats sur le front occidental", explanation: "L'armistice est signé le 11 novembre 1918 à 5h du matin dans un wagon-restaurant dans la forêt de Compiègne (Rethondes). Les combats cessent à 11h du matin (11e heure du 11e jour du 11e mois). L'Allemagne, épuisée par les offensives alliées et la révolution intérieure (abdication du Kaiser Guillaume II le 9 novembre), demande l'armistice. Ce n'est pas une capitulation mais une cessation des combats, en attendant le traité de paix de Versailles (1919).", difficulty: 1, points: 10 },
  { id: 'q_1e_11', level: '1ere', theme: 'Vichy et collaboration', question: "Qu'est-ce que la 'Révolution nationale' du régime de Vichy ?", options: ["Une révolution démocratique pour réformer la France", "Le programme idéologique de Vichy remplaçant Liberté-Égalité-Fraternité par Travail-Famille-Patrie, rejetant les valeurs républicaines", "Une révolution militaire pour libérer la France de l'Allemagne", "Un programme économique inspiré du nazisme"], answer: "Le programme idéologique de Vichy remplaçant Liberté-Égalité-Fraternité par Travail-Famille-Patrie, rejetant les valeurs républicaines", explanation: "La 'Révolution nationale' est le programme idéologique du régime de Vichy. Elle remplace la devise républicaine (Liberté, Égalité, Fraternité) par Travail, Famille, Patrie. Elle glorifie le travail paysan et artisanal, la famille nombreuse, le catholicisme, la discipline. Elle rejette le parlementarisme, l'individualisme, le marxisme et le cosmopolitisme. C'est un retour aux valeurs traditionnelles conservatrices en réaction contre ce que Vichy appelle la 'décadence' républicaine.", difficulty: 2, points: 10 },
  { id: 'q_1e_12', level: '1ere', theme: 'Vichy et collaboration', question: "Qu'est-ce que l'entrevue de Montoire (24 octobre 1940) signifie ?", options: ["Pétain refuse de collaborer avec l'Allemagne", "Pétain serre la main d'Hitler et annonce 'entrer dans la voie de la collaboration' — choix politique délibéré", "De Gaulle rencontre Churchill à Londres", "L'armistice est signé entre la France et l'Allemagne"], answer: "Pétain serre la main d'Hitler et annonce 'entrer dans la voie de la collaboration' — choix politique délibéré", explanation: "Le 24 octobre 1940, à Montoire-sur-le-Loir, Pétain rencontre Hitler et lui serre la main (photographié et filmé). Il annonce à la radio : 'C'est dans l'honneur et pour maintenir l'unité française que j'entre aujourd'hui dans la voie de la collaboration.' Cette formule prouve que la collaboration est un choix délibéré de Vichy, non une contrainte imposée par l'occupant. Elle choque les Français libres à Londres.", difficulty: 2, points: 10 },
  { id: 'q_1e_13', level: '1ere', theme: 'Guerre Froide', question: "Qu'est-ce que le plan Marshall (juin 1947) et pourquoi l'URSS le refuse-t-elle ?", options: ["Un plan militaire américain — l'URSS le refuse car elle a sa propre armée", "Une aide économique américaine à l'Europe — l'URSS le refuse car il renforcerait l'influence américaine et affaiblirait le communisme en Europe", "Un plan de désarmement — l'URSS le refuse car elle veut maintenir son armée", "Un accord commercial — l'URSS le refuse car elle n'a pas besoin d'aide"], answer: "Une aide économique américaine à l'Europe — l'URSS le refuse car il renforcerait l'influence américaine et affaiblirait le communisme en Europe", explanation: "Le plan Marshall (juin 1947) propose 13 milliards de dollars pour reconstruire les économies européennes. Son objectif est d'empêcher que la misère pousse les populations européennes vers le communisme. L'URSS (Molotov) refuse et oblige ses satellites à refuser également, estimant que c'est un instrument d'impérialisme américain. En réponse, l'URSS crée le Kominform (bureau d'information communiste) et le plan Molotov/CAEM.", difficulty: 2, points: 10 },
  { id: 'q_1e_14', level: '1ere', theme: 'Guerre Froide', question: "En quelle année est créée l'OTAN et quels pays en sont les membres fondateurs ?", options: ["1947, USA et France uniquement", "1949, 12 pays : USA, Canada, France, Royaume-Uni, Belgique, Pays-Bas, Luxembourg, Italie, Portugal, Islande, Norvège, Danemark", "1955, en réponse au Pacte de Varsovie", "1944, pendant la Seconde Guerre mondiale"], answer: "1949, 12 pays : USA, Canada, France, Royaume-Uni, Belgique, Pays-Bas, Luxembourg, Italie, Portugal, Islande, Norvège, Danemark", explanation: "L'Organisation du Traité de l'Atlantique Nord (OTAN) est créée le 4 avril 1949 à Washington par 12 pays fondateurs. Son principe central (article 5) : une attaque contre l'un est une attaque contre tous. En réponse, l'URSS crée le Pacte de Varsovie en 1955 (avec ses satellites d'Europe de l'Est). La France se retire du commandement intégré en 1966 (De Gaulle) et y revient en 2009 (Sarkozy).", difficulty: 2, points: 10 },

  // ========== Terminale (nouvelles questions) ==========
  { id: 'q_term_04', level: 'Terminale', theme: 'Mondialisation', question: "Quelles sont les caractéristiques de la mondialisation contemporaine ?", options: ["La mondialisation se limite aux échanges commerciaux de marchandises", "La mondialisation connecte les économies, les sociétés et les cultures mondiales par les flux de capitaux, de marchandises, d'informations et de personnes", "La mondialisation bénéficie également à tous les pays du monde", "La mondialisation est un phénomène entièrement nouveau né après 1991"], answer: "La mondialisation connecte les économies, les sociétés et les cultures mondiales par les flux de capitaux, de marchandises, d'informations et de personnes", explanation: "La mondialisation contemporaine est multidimensionnelle : flux de capitaux (marchés financiers 24h/24), de marchandises (conteneurisation, OMC), d'informations (internet, réseaux sociaux), de personnes (migrations, tourisme). Elle crée des interdépendances mais aussi des inégalités (entre pays du Nord et du Sud, entre gagnants et perdants de la mondialisation au sein de chaque pays). Elle s'accélère depuis les années 1980-1990.", difficulty: 2, points: 10 },
  { id: 'q_term_05', level: 'Terminale', theme: 'Environnement', question: "Qu'est-ce que l'Accord de Paris (2015) sur le climat et quelles sont ses limites ?", options: ["Un accord militaire pour protéger les zones climatiques sensibles", "Un accord entre 196 pays visant à limiter le réchauffement à 2°C (idéalement 1,5°C) — mais sans mécanisme contraignant de vérification", "Un accord commercial liant les émissions de CO2 aux échanges internationaux", "Un accord bilatéral entre USA et Chine sur le climat"], answer: "Un accord entre 196 pays visant à limiter le réchauffement à 2°C (idéalement 1,5°C) — mais sans mécanisme contraignant de vérification", explanation: "L'Accord de Paris (COP21, décembre 2015) est signé par 196 pays. Il vise à maintenir le réchauffement climatique bien en dessous de 2°C par rapport aux niveaux préindustriels (idéalement 1,5°C). Chaque pays soumet ses propres contributions (NDC) sans mécanisme contraignant de vérification. Ses limites : Trump retire les USA en 2017 (ils reviennent en 2021), les NDC actuelles sont insuffisantes pour atteindre l'objectif, les pays en développement réclament un financement climatique adéquat.", difficulty: 2, points: 10 },
  { id: 'q_term_06', level: 'Terminale', theme: 'Puissances régionales', question: "Pourquoi la Chine est-elle considérée comme une puissance mondiale émergente au XXIe siècle ?", options: ["Parce qu'elle vient de développer l'arme nucléaire", "Parce qu'elle combine la 2e économie mondiale, l'armée la plus nombreuse, une puissance diplomatique croissante et les nouvelles routes de la soie", "Parce qu'elle est membre fondateur de l'ONU", "Parce qu'elle a rejoint l'OTAN en 2001"], answer: "Parce qu'elle combine la 2e économie mondiale, l'armée la plus nombreuse, une puissance diplomatique croissante et les nouvelles routes de la soie", explanation: "La Chine est devenue la 2e puissance économique mondiale (elle pourrait dépasser les USA d'ici 2030). Elle combine : une puissance économique (croissance de 6-10% pendant 30 ans, atelier du monde), militaire (armée la plus nombreuse, modernisation accélérée, îles artificielles en mer de Chine), diplomatique (routes de la soie BRI, présence en Afrique, Asie, Amérique latine), technologique (Huawei, IA, spatial). Xi Jinping ambitionne que la Chine soit une puissance mondiale dominante en 2049.", difficulty: 2, points: 10 },
  { id: 'q_term_07', level: 'Terminale', theme: 'Puissances régionales', question: "Qu'est-ce que le concept de 'Sud global' et pourquoi est-il contesté ?", options: ["Un terme géographique désignant l'hémisphère sud de la planète", "Un concept politique regroupant les pays en développement (anciennement Tiers Monde) qui s'affirment face aux puissances occidentales — mais contesté car il masque des réalités très diverses", "Un bloc économique alternatif au G7", "Une alliance militaire des pays du sud"], answer: "Un concept politique regroupant les pays en développement (anciennement Tiers Monde) qui s'affirment face aux puissances occidentales — mais contesté car il masque des réalités très diverses", explanation: "Le 'Sud global' désigne les pays d'Afrique, d'Asie, d'Amérique latine et d'Océanie historiquement colonisés et économiquement dominés. Il remplace des termes anciens (Tiers Monde, pays en développement). Depuis les années 2010, ces pays s'affirment : refus de s'aligner sur les sanctions contre la Russie (2022), revendications au G20, montée en puissance de la Chine, de l'Inde, du Brésil. Mais le terme masque des réalités très diverses : entre le Qatar et le Mali, les différences sont immenses.", difficulty: 3, points: 10 },

  // ========== HGGSP (nouvelles questions) ==========
  { id: 'q_hggsp_05', level: 'HGGSP', theme: 'Cyberpuissance', question: "Qu'est-ce que la cyberpuissance et quels États en sont les principales puissances ?", options: ["La puissance électrique d'un État", "La capacité à agir dans le cyberespace pour défendre ses intérêts et attaquer ceux des autres — USA, Chine, Russie, Israël en tête", "La puissance des réseaux sociaux d'un pays", "La capacité à produire des ordinateurs et téléphones"], answer: "La capacité à agir dans le cyberespace pour défendre ses intérêts et attaquer ceux des autres — USA, Chine, Russie, Israël en tête", explanation: "La cyberpuissance est la capacité d'un acteur (État, groupe) à utiliser le cyberespace pour surveiller (espionnage, NSA/GCHQ), attaquer (cyberattaques sur infrastructures : Stuxnet contre l'Iran 2010, cyberattaques russes sur l'Ukraine), désinformer (influence sur les réseaux sociaux) ou se défendre. Les principales cyberpuissances sont les USA, la Chine, la Russie, Israël et le Royaume-Uni. Le cyberespace est le 5e domaine de conflictualité après la terre, la mer, l'air et l'espace.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_06', level: 'HGGSP', theme: 'Opinion publique et médias', question: "Comment les réseaux sociaux transforment-ils la formation de l'opinion publique ?", options: ["Ils n'ont aucun impact car les gens restent attachés aux médias traditionnels", "Ils permettent la désinformation de masse, les chambres d'écho, le contournement des médias traditionnels et la polarisation de l'opinion", "Ils améliorent la qualité du débat démocratique en donnant la parole à tous", "Ils sont contrôlés par les gouvernements et diffusent uniquement des informations officielles"], answer: "Ils permettent la désinformation de masse, les chambres d'écho, le contournement des médias traditionnels et la polarisation de l'opinion", explanation: "Les réseaux sociaux (Facebook, Twitter/X, TikTok) transforment profondément l'opinion publique : ils créent des 'chambres d'écho' (algorithmes qui renforcent les opinions préexistantes), permettent la désinformation virale (infox, théories du complot), contournent les gatekeepers traditionnels (journaux, télévisions), facilitent la manipulation politique (Cambridge Analytica, trolls russes en 2016). La polarisation politique s'accentue. Les démocraties cherchent à réguler sans censurer.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_07', level: 'HGGSP', theme: 'Justice internationale', question: "Qu'est-ce que la Cour Pénale Internationale (CPI) et quelles sont ses limites ?", options: ["Un tribunal de l'ONU jugeant les États", "Un tribunal permanent jugeant les individus pour crimes contre l'humanité, génocide et crimes de guerre — mais limité par le refus de grandes puissances d'y adhérer", "Un tribunal arbitral pour les conflits commerciaux internationaux", "La Cour Internationale de Justice de La Haye"], answer: "Un tribunal permanent jugeant les individus pour crimes contre l'humanité, génocide et crimes de guerre — mais limité par le refus de grandes puissances d'y adhérer", explanation: "La CPI (créée par le statut de Rome en 1998, en vigueur depuis 2002, siège à La Haye) est le premier tribunal pénal international permanent. Elle juge les individus (pas les États) pour crimes de guerre, crimes contre l'humanité et génocide. Ses limites : les USA, la Russie, la Chine et l'Inde n'ont pas ratifié le statut de Rome et refusent sa juridiction. Elle ne peut juger que les ressortissants de ses États membres ou si le Conseil de Sécurité la saisit (avec droit de veto). Elle a émis un mandat contre Poutine en 2023.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_08', level: 'HGGSP', theme: 'Migrations', question: "Comment distinguer un migrant économique d'un réfugié au sens de la Convention de Genève (1951) ?", options: ["Il n'y a aucune différence juridique entre les deux", "Le réfugié fuit une persécution individuelle (guerre, politique, religion) et bénéficie d'une protection internationale — le migrant économique cherche de meilleures conditions de vie sans persécution reconnue", "Le réfugié vient d'un pays pauvre, le migrant d'un pays riche", "Le migrant est illégal, le réfugié est légal dans tous les cas"], answer: "Le réfugié fuit une persécution individuelle (guerre, politique, religion) et bénéficie d'une protection internationale — le migrant économique cherche de meilleures conditions de vie sans persécution reconnue", explanation: "La Convention de Genève (1951) définit le réfugié comme toute personne qui craint avec raison d'être persécutée du fait de sa race, sa religion, sa nationalité, ses opinions politiques ou son appartenance à un groupe social. Le réfugié bénéficie du droit d'asile et ne peut être renvoyé dans son pays (non-refoulement). Le migrant économique fuit la pauvreté ou cherche de meilleures opportunités — il n'a pas droit automatiquement à l'asile mais peut bénéficier d'autres protections. Dans la réalité, les deux catégories se mêlent souvent.", difficulty: 3, points: 10 },

  // ========== 6e — questions supplémentaires ==========
  { id: 'q_6e_11', level: '6e', theme: 'Préhistoire', question: "Qu'est-ce que Lascaux et que nous apprend ce site ?", options: ["Une ville romaine en Gaule", "Une grotte ornée (-17 000 ans) avec des peintures rupestres de bisons, chevaux et cerfs", "Un site funéraire mégalithique", "Un camp militaire de Jules César"], answer: "Une grotte ornée (-17 000 ans) avec des peintures rupestres de bisons, chevaux et cerfs", explanation: "Lascaux (Dordogne, France) est une grotte ornée datant d'environ 17 000 ans. Elle contient plus de 2 000 figures animales (bisons, chevaux, cerfs, rhinocéros). Ces peintures témoignent d'une pensée symbolique et artistique élaborée chez Homo sapiens. Découverte en 1940, fermée au public depuis 1963 (détérioration), remplacée par Lascaux IV.", difficulty: 1, points: 10 },
  { id: 'q_6e_12', level: '6e', theme: 'Égypte antique', question: "Que signifie la mort et la vie après la mort dans la religion égyptienne ?", options: ["Les Égyptiens ne croient pas en une vie après la mort", "La mort est un passage vers une autre vie — le ka (âme) continue si le corps est préservé (momification) et les rites funéraires respectés", "Les Égyptiens croient en la réincarnation comme les bouddhistes", "Seuls les pharaons ont une vie après la mort"], answer: "La mort est un passage vers une autre vie — le ka (âme) continue si le corps est préservé (momification) et les rites funéraires respectés", explanation: "Pour les Égyptiens, la mort est un passage vers l'Au-delà. Le ka (énergie vitale) et le ba (âme individuelle) doivent pouvoir retrouver le corps. D'où la momification : le corps est embaumé, les organes placés dans des vases canopes, le tout dans un sarcophage. Le défunt est jugé par Osiris : son cœur est pesé contre une plume de Maât (justice). Si son cœur est pur, il accède à l'Au-delà.", difficulty: 2, points: 10 },
  { id: 'q_6e_13', level: '6e', theme: 'Grèce antique', question: "Quelle est la différence entre Athènes et Sparte dans l'Antiquité grecque ?", options: ["Il n'y a pas de différence, elles sont alliées permanentes", "Athènes = démocratie, culture, commerce maritime / Sparte = oligarchie militaire, austérité, armée terrestre", "Sparte est démocratique et Athènes est monarchique", "Athènes est en Asie, Sparte en Europe"], answer: "Athènes = démocratie, culture, commerce maritime / Sparte = oligarchie militaire, austérité, armée terrestre", explanation: "Ces deux cités incarnent des modèles opposés : Athènes développe la démocratie, la philosophie (Socrate, Platon), les arts (Parthénon), le commerce maritime. Sparte est une société militaire : les garçons intègrent l'agôgê (entraînement militaire) dès 7 ans, les femmes ont un rôle plus actif. Sparte est gouvernée par deux rois et un conseil d'anciens (Gérousia). Elles s'affrontent lors de la guerre du Péloponnèse (-431 à -404), remportée par Sparte.", difficulty: 2, points: 10 },
  { id: 'q_6e_14', level: '6e', theme: 'Rome antique', question: "Qu'est-ce que le Colisée et à quoi servait-il ?", options: ["Un temple dédié à Jupiter", "Un amphithéâtre romain pouvant accueillir 50 000 spectateurs pour des combats de gladiateurs et des spectacles", "Le palais des empereurs romains", "Un marché romain couvert"], answer: "Un amphithéâtre romain pouvant accueillir 50 000 spectateurs pour des combats de gladiateurs et des spectacles", explanation: "Le Colisée (Flavius Amphitheatrum), construit entre 70 et 80 ap. J.-C. sous les empereurs Vespasien et Titus, est le plus grand amphithéâtre romain. Il accueille jusqu'à 50 000 spectateurs pour des munera (combats de gladiateurs), des venationes (chasses d'animaux), des exécutions publiques et parfois des naumachies (batailles navales simulées). Symbole du pain et des jeux (panem et circenses) pour contrôler la plèbe.", difficulty: 1, points: 10 },
  { id: 'q_6e_15', level: '6e', theme: 'Mésopotamie', question: "Qui est Alexandre le Grand et quelle est son importance historique ?", options: ["Un pharaon égyptien qui a construit des pyramides", "Un roi macédonien (-356/-323) qui conquiert un empire de la Grèce à l'Inde en 13 ans et diffuse la culture grecque", "Un général romain qui a conquis la Gaule", "Un calife arabe fondateur de l'islam"], answer: "Un roi macédonien (-356/-323) qui conquiert un empire de la Grèce à l'Inde en 13 ans et diffuse la culture grecque", explanation: "Alexandre III de Macédoine (dit 'le Grand', -356/-323) est le fils du roi Philippe II, éduqué par Aristote. En 13 ans de conquêtes, il bat l'Empire perse achéménide, conquiert l'Égypte (fondation d'Alexandrie), la Mésopotamie, la Perse, la Bactriane et l'Inde. Il crée l'hellénisme : diffusion de la langue et de la culture grecques de la Méditerranée à l'Inde. Son empire se divise après sa mort à Babylone (323 av. J.-C.).", difficulty: 2, points: 10 },

  // ========== 5e — questions supplémentaires ==========
  { id: 'q_5e_10', level: '5e', theme: 'Moyen Âge', question: "Qu'est-ce qu'une cathédrale gothique et en quoi diffère-t-elle de l'art roman ?", options: ["Une mosquée médiévale transformée en église", "Un type d'église médiévale caractérisé par les ogives, les arcs-boutants et les grandes verrières — plus légère et haute que le style roman", "Un château-fort transformé en lieu de culte", "Une église simple sans ornements"], answer: "Un type d'église médiévale caractérisé par les ogives, les arcs-boutants et les grandes verrières — plus légère et haute que le style roman", explanation: "L'art gothique (XIIe-XVe siècles) révolutionne l'architecture religieuse : les voûtes en ogive répartissent mieux les forces, les arcs-boutants extérieurs permettent d'alléger les murs et d'agrandir les fenêtres. Résultat : des cathédrales de plus en plus hautes et lumineuses (Notre-Dame de Paris, Chartres, Reims). Contraste avec l'art roman : murs épais, petites fenêtres, aspect trapu mais solide.", difficulty: 2, points: 10 },
  { id: 'q_5e_11', level: '5e', theme: 'Grandes Découvertes', question: "Quel est l'impact des épidémies sur les populations amérindiennes après 1492 ?", options: ["Les épidémies sont peu nombreuses car les Amérindiens sont immunisés", "La population amérindienne s'effondre de 80 à 90% en un siècle à cause de maladies européennes (variole, rougeole) contre lesquelles ils n'ont aucune immunité", "Les Espagnols apportent des vaccins qui protègent les Amérindiens", "Les épidémies touchent surtout les Espagnols en Amérique"], answer: "La population amérindienne s'effondre de 80 à 90% en un siècle à cause de maladies européennes (variole, rougeole) contre lesquelles ils n'ont aucune immunité", explanation: "L'une des conséquences les plus dévastatrices de la Conquête : la variole, la rougeole, la grippe et d'autres maladies européennes déciment les populations amérindiennes, qui n'ont aucune immunité contre ces pathogènes. Au Mexique, la population passe de ~25 millions en 1519 à ~1 million en 1600. C'est l'un des génocides démographiques les plus importants de l'Histoire. Cette dépopulation entraîne la traite négrière pour remplacer la main d'œuvre.", difficulty: 2, points: 10 },
  { id: 'q_5e_12', level: '5e', theme: 'Moyen Âge', question: "Qu'est-ce qu'un seigneur dans la société féodale médiévale ?", options: ["Un prêtre catholique de haut rang", "Un noble propriétaire d'un fief qui protège ses vassaux et paysans (serfs) en échange de redevances et de services", "Un roi qui gouverne l'ensemble du royaume", "Un marchand riche qui prête de l'argent aux nobles"], answer: "Un noble propriétaire d'un fief qui protège ses vassaux et paysans (serfs) en échange de redevances et de services", explanation: "Le seigneur est un noble qui possède une terre (fief) avec un château. Il doit protection à ses vassaux (autres nobles liés par un serment) et à ses paysans (serfs ou vilains). En échange, les paysans paient des redevances (champart sur les récoltes, cens annuel) et des taxes (banalités pour le moulin, le four, le pressoir), et doivent parfois des corvées. Cette organisation est la base de la société médiévale.", difficulty: 1, points: 10 },

  // ========== 4e — questions supplémentaires ==========
  { id: 'q_4e_06', level: '4e', theme: 'Révolution française', question: "Qu'est-ce que la DDHC (Déclaration des Droits de l'Homme et du Citoyen, 1789) ?", options: ["Une loi sur l'abolition de la monarchie", "Un texte fondateur posant les droits naturels universels : liberté, propriété, sûreté, résistance à l'oppression", "Un règlement intérieur de l'Assemblée nationale", "Un traité international signé avec l'Angleterre"], answer: "Un texte fondateur posant les droits naturels universels : liberté, propriété, sûreté, résistance à l'oppression", explanation: "Adoptée le 26 août 1789, la DDHC est un texte de 17 articles inspiré des Lumières et de la Déclaration d'indépendance américaine. Elle proclame que les hommes naissent libres et égaux en droits, et définit 4 droits naturels imprescriptibles : liberté, propriété, sûreté, résistance à l'oppression. La souveraineté appartient à la nation. Ce texte devient le fondement des démocraties modernes.", difficulty: 2, points: 10 },
  { id: 'q_4e_07', level: '4e', theme: 'Révolution industrielle', question: "Pourquoi la révolution industrielle commence-t-elle en Angleterre et pas ailleurs ?", options: ["L'Angleterre a le meilleur climat pour l'industrie", "L'Angleterre combine charbon abondant, empire colonial, main d'œuvre exodée, capitaux disponibles et liberté d'entreprendre", "L'Angleterre reçoit l'aide de la France pour s'industrialiser", "Les inventeurs anglais sont plus intelligents que les autres"], answer: "L'Angleterre combine charbon abondant, empire colonial, main d'œuvre exodée, capitaux disponibles et liberté d'entreprendre", explanation: "L'Angleterre est pionnière pour plusieurs raisons cumulées : charbon et fer abondants (Pays de Galles, Midlands) ; empire colonial qui fournit matières premières et marchés ; révolution agricole préalable (enclosures) qui libère une main d'œuvre paysanne ; capitaux disponibles (banques, actionnaires) ; liberté d'entreprendre (liberté du commerce depuis 1651) ; inventeurs et ingénieurs (Watt, Arkwright, Stephenson). La France suit 30-40 ans plus tard.", difficulty: 2, points: 10 },
  { id: 'q_4e_08', level: '4e', theme: 'Colonisation', question: "Qu'est-ce que le commerce triangulaire et combien d'Africains concerne-t-il ?", options: ["Un commerce entre 3 villes européennes", "Un système reliant Europe, Afrique et Amériques : armes contre esclaves africains, vendus aux Amériques contre produits tropicaux — 12 millions d'Africains déportés", "Un accord commercial entre France, Espagne et Portugal", "Un commerce de 3 produits : sucre, tabac, coton"], answer: "Un système reliant Europe, Afrique et Amériques : armes contre esclaves africains, vendus aux Amériques contre produits tropicaux — 12 millions d'Africains déportés", explanation: "Le commerce triangulaire (XVIe-XIXe siècles) fonctionne en 3 étapes : 1) Europe → Afrique : tissus, armes, alcool échangés contre des esclaves ; 2) Afrique → Amériques (traite négrière) : traversée de l'Atlantique (Middle Passage) dans des conditions épouvantables (15-20% de mortalité) ; 3) Amériques → Europe : sucre, tabac, coton, café. Environ 12 millions d'Africains sont déportés entre 1500 et 1850. Ce commerce enrichit les ports européens (Nantes, Bordeaux, Bristol, Liverpool).", difficulty: 2, points: 10 },
  { id: 'q_4e_09', level: '4e', theme: 'Napoléon', question: "Quelles sont les principales batailles de Napoléon et lesquelles sont des défaites ?", options: ["Austerlitz (victoire) et Waterloo (victoire)", "Austerlitz 1805 (victoire décisive) et Waterloo 1815 (défaite définitive)", "Borodino (victoire) et Trafalgar (victoire)", "Iéna (défaite) et Wagram (victoire)"], answer: "Austerlitz 1805 (victoire décisive) et Waterloo 1815 (défaite définitive)", explanation: "Parmi les principales batailles napoléoniennes : Victoires — Austerlitz (2 déc. 1805, contre Autriche+Russie, chef-d'œuvre tactique), Iéna (1806, contre Prusse), Wagram (1809, contre Autriche) ; Défaites — Trafalgar (21 oct. 1805, flotte française détruite par Nelson), Moscou (1812, victoire à la Pyrrhus : la retraite de Russie détruit la Grande Armée), Leipzig (1813, bataille des Nations), Waterloo (18 juin 1815, contre Wellington+Blücher, fin définitive de l'Empire).", difficulty: 2, points: 10 },
  { id: 'q_4e_10', level: '4e', theme: 'Lumières', question: "Quel est le projet de l'Encyclopédie de Diderot et d'Alembert (1751-1772) ?", options: ["Recenser toutes les espèces animales connues", "Rassembler et diffuser tous les savoirs humains pour lutter contre l'ignorance et le fanatisme, au service de la raison", "Traduire la Bible en français pour le peuple", "Créer un dictionnaire de la langue française"], answer: "Rassembler et diffuser tous les savoirs humains pour lutter contre l'ignorance et le fanatisme, au service de la raison", explanation: "L'Encyclopédie ou Dictionnaire raisonné des sciences, des arts et des métiers (1751-1772) de Diderot et d'Alembert rassemble 28 volumes et 71 000 articles rédigés par les meilleurs esprits (Voltaire, Rousseau, Montesquieu). Son objectif est de diffuser les Lumières : rassembler tous les savoirs, critiquer les superstitions et le fanatisme religieux, promouvoir la tolérance et la raison. L'Église et le gouvernement royaliste tentent de l'interdire. C'est un acte politique autant qu'intellectuel.", difficulty: 2, points: 10 },
  { id: 'q_4e_11', level: '4e', theme: 'Révolution américaine', question: "Quel est le principe fondamental de la Déclaration d'Indépendance américaine (1776) ?", options: ["L'indépendance de chaque État américain vis-à-vis des autres", "Que tous les hommes sont créés égaux et ont des droits inaliénables (vie, liberté, bonheur) — le gouvernement tient son pouvoir du consentement des gouvernés", "La supériorité de la religion protestante sur le catholicisme", "La séparation stricte de l'Église et de l'État"], answer: "Que tous les hommes sont créés égaux et ont des droits inaliénables (vie, liberté, bonheur) — le gouvernement tient son pouvoir du consentement des gouvernés", explanation: "Rédigée principalement par Thomas Jefferson, la Déclaration d'Indépendance (4 juillet 1776) pose que : 'Nous tenons ces vérités pour évidentes : tous les hommes sont créés égaux, ils sont dotés de droits inaliénables, parmi lesquels la vie, la liberté et la recherche du bonheur.' Le gouvernement tient ses pouvoirs du consentement des gouvernés. Si le gouvernement viole ces droits, le peuple a le droit de le renverser. Cette déclaration inspire la Révolution française (1789).", difficulty: 2, points: 10 },
  { id: 'q_4e_12', level: '4e', theme: 'Révolution industrielle', question: "Qu'est-ce que le mouvement ouvrier et quels sont ses principaux combats au XIXe siècle ?", options: ["Un mouvement de danse populaire au XIXe siècle", "Le mouvement de défense des droits des travailleurs : réduction du temps de travail, droit syndical, suffrage universel, fin du travail des enfants", "Un mouvement de travailleurs pour défendre les machines contre les patrons", "Un parti politique fondé par Karl Marx"], answer: "Le mouvement de défense des droits des travailleurs : réduction du temps de travail, droit syndical, suffrage universel, fin du travail des enfants", explanation: "La révolution industrielle engendre des conditions de travail catastrophiques : 12-16h/jour, enfants au travail dès 6 ans, aucune protection sociale. Le mouvement ouvrier se structure pour combattre ces abus : création de syndicats (Trade Unions en Angleterre dès 1824, autorisés en France en 1884), revendication du suffrage universel (chartisme britannique), journée de 8h (1er mai 1886 à Chicago), interdiction du travail des enfants. Karl Marx publie le Manifeste communiste en 1848.", difficulty: 2, points: 10 },

  // ========== 3e — questions supplémentaires ==========
  { id: 'q_3e_09', level: '3e', theme: 'Seconde Guerre mondiale', question: "Qu'est-ce que la Shoah et quand est-elle planifiée ?", options: ["La destruction des grandes villes européennes par les bombardements", "Le génocide des Juifs d'Europe par les nazis : 6 millions de morts, planifié lors de la conférence de Wannsee (20 janvier 1942)", "L'expulsion des populations juives d'Allemagne en 1933", "Les combats entre armées sur le front est"], answer: "Le génocide des Juifs d'Europe par les nazis : 6 millions de morts, planifié lors de la conférence de Wannsee (20 janvier 1942)", explanation: "La Shoah (mot hébreu signifiant 'catastrophe') est le génocide systématique des Juifs d'Europe par le régime nazi. Elle passe par plusieurs phases : lois anti-juives (lois de Nuremberg 1935), pogroms (Nuit de Cristal 1938), ghettos (Varsovie), Einsatzgruppen (fusillades en masse, 1941), puis la 'solution finale' : camps d'extermination (Auschwitz-Birkenau, Treblinka, Sobibor). La conférence de Wannsee (20 jan. 1942) coordonne l'extermination. 6 millions de Juifs sont assassinés, soit 2/3 des Juifs d'Europe.", difficulty: 2, points: 10 },
  { id: 'q_3e_10', level: '3e', theme: 'Première Guerre mondiale', question: "Qu'est-ce que la 'guerre totale' caractérisant la Première Guerre mondiale ?", options: ["Une guerre qui se déroule sur tous les continents", "Une mobilisation de toute la société (économie, femmes, colonies, propagande, opinion publique) pour soutenir l'effort de guerre — pas seulement les armées", "Une guerre qui dure toute l'année sans trêve", "Une guerre où toutes les armes sont autorisées"], answer: "Une mobilisation de toute la société (économie, femmes, colonies, propagande, opinion publique) pour soutenir l'effort de guerre — pas seulement les armées", explanation: "La guerre totale implique que l'ensemble de la société est mobilisée : économiquement (usines reconverties en arsenaux, femmes remplaçant les hommes), colonialement (soldats sénégalais, indiens, australiens), psychologiquement (propagande nationaliste, bourrage de crâne), financièrement (emprunts de guerre). Les fronts et l'arrière sont interdépendants. La frontière entre combattants et civils s'efface (bombardements de villes, blocus maritime, famines).", difficulty: 2, points: 10 },
  { id: 'q_3e_11', level: '3e', theme: 'Montée du fascisme', question: "Quelles sont les caractéristiques du régime totalitaire nazi ?", options: ["Un régime parlementaire dominé par un seul parti", "Parti unique (NSDAP), chef charismatique (Führer), idéologie raciste (antisémitisme, Herrenvolk), terreur (Gestapo, SS), propagande permanente (Goebbels)", "Un régime militaire sans idéologie politique", "Un régime démocratique avec un Parlement contrôlé"], answer: "Parti unique (NSDAP), chef charismatique (Führer), idéologie raciste (antisémitisme, Herrenvolk), terreur (Gestapo, SS), propagande permanente (Goebbels)", explanation: "Le régime nazi (1933-1945) est le modèle du totalitarisme : un seul parti (NSDAP), un chef absolu (Hitler = Führer, guide), une idéologie raciste (supériorité de la race aryenne, antisémitisme), un appareil de terreur (Gestapo, SS, camps de concentration), une propagande omniprésente (Goebbels, films de Riefenstahl, Jeux Olympiques de 1936). L'individu est totalement soumis à l'État et à la race.", difficulty: 2, points: 10 },
  { id: 'q_3e_12', level: '3e', theme: 'Guerre Froide', question: "Pourquoi la crise des missiles de Cuba (octobre 1962) est-elle le moment le plus dangereux de la Guerre Froide ?", options: ["Parce que les USA et l'URSS se déclarent mutuellement la guerre", "Parce que l'URSS installe des missiles nucléaires à Cuba, à 150 km des USA — les deux superpuissances sont à quelques heures d'un conflit nucléaire mondial", "Parce que Cuba attaque la Floride", "Parce que Kennedy ordonne une invasion de Cuba"], answer: "Parce que l'URSS installe des missiles nucléaires à Cuba, à 150 km des USA — les deux superpuissances sont à quelques heures d'un conflit nucléaire mondial", explanation: "En octobre 1962, les États-Unis découvrent (U-2) que l'URSS installe des missiles nucléaires à Cuba (à 150 km de la Floride). Kennedy impose un blocus naval. Pendant 13 jours, le monde est au bord de la guerre nucléaire. La crise se résout diplomatiquement : Khrouchtchev retire les missiles soviétiques de Cuba, Kennedy s'engage à ne pas envahir Cuba et retire discrètement des missiles US de Turquie. Un téléphone rouge (hotline) est installé entre Washington et Moscou.", difficulty: 2, points: 10 },
  { id: 'q_3e_13', level: '3e', theme: 'Décolonisation', question: "Comment l'Algérie acquiert-elle son indépendance et à quel prix ?", options: ["Par une négociation pacifique avec la France dès 1954", "Par une guerre de 8 ans (1954-1962) : 300 000 à 1 million de morts algériens, 25 000 soldats français, aboutissant aux accords d'Évian", "Par un vote à l'ONU imposant l'indépendance à la France", "Par une invasion de l'armée égyptienne qui libère l'Algérie"], answer: "Par une guerre de 8 ans (1954-1962) : 300 000 à 1 million de morts algériens, 25 000 soldats français, aboutissant aux accords d'Évian", explanation: "La guerre d'Algérie (1er novembre 1954 - 19 mars 1962) est l'une des décolonisations les plus violentes. Le FLN déclenche une insurrection armée. La France répond par l'envoi de 450 000 soldats, le recours à la torture (qui provoque des débats en France), les 'événements' (euphémisme officiel). 8 ans de guerre causent 300 000 à 1 million de morts algériens, 25 000 soldats français. Les accords d'Évian (19 mars 1962) accordent l'indépendance. 1 million de pieds-noirs fuient l'Algérie.", difficulty: 2, points: 10 },
  { id: 'q_3e_14', level: '3e', theme: 'Construction européenne', question: "Quelles sont les grandes étapes de la construction européenne de 1957 à aujourd'hui ?", options: ["CEE (1957) → Marché unique (1986) → Maastricht et UE (1992) → Euro (2002) → 27 membres", "EEC (1945) → OTAN (1949) → UE (1960)", "Traité de Paris (1951, CECA) → Rome (1957, CEE) → Maastricht (1992, UE) → Lisbonne (2007) → Brexit (2020, -1)", "Gaulle (1958) → Pompidou (1969) → Mitterrand (1981) → Union européenne"], answer: "Traité de Paris (1951, CECA) → Rome (1957, CEE) → Maastricht (1992, UE) → Lisbonne (2007) → Brexit (2020, -1)", explanation: "Grandes étapes : 1951 : CECA (Communauté Européenne du Charbon et de l'Acier, 6 pays fondateurs) ; 1957 : traité de Rome → CEE (marché commun) ; 1979 : premières élections au Parlement européen ; 1986 : Acte unique (marché unique sans frontières) ; 1992 : traité de Maastricht → UE, citoyenneté européenne, euro prévu ; 2002 : introduction de l'euro (12 pays) ; 2007 : traité de Lisbonne (réforme institutionnelle) ; 2020 : Brexit (Royaume-Uni quitte l'UE). Aujourd'hui : 27 membres.", difficulty: 3, points: 10 },

  // ========== 2nde — questions supplémentaires ==========
  { id: 'q_2nde_11', level: '2nde', theme: 'Humanisme', question: "Qu'est-ce que l'humanisme de la Renaissance et en quoi rompt-il avec le Moyen Âge ?", options: ["Un mouvement athée qui rejette la religion", "Un courant intellectuel plaçant l'homme au centre de la réflexion, valorisant l'Antiquité gréco-latine et la raison — rompt avec la théocentrisme médiéval", "Un mouvement social défendant les droits des pauvres", "Un courant artistique uniquement pictural"], answer: "Un courant intellectuel plaçant l'homme au centre de la réflexion, valorisant l'Antiquité gréco-latine et la raison — rompt avec la théocentrisme médiéval", explanation: "L'humanisme (XVe-XVIe siècles) place l'homo (l'homme) au centre de la réflexion. Les humanistes (Érasme, Rabelais, Montaigne) étudient les textes grecs et latins (studia humanitatis), valorisent la raison et l'expérience, croient en la perfectibilité humaine. Ce faisant, ils rompent avec le théocentrisme médiéval (où tout part de Dieu et y revient). L'homme est créateur, chercheur, artiste. Le Pape reste important mais la Bible est lue directement (Érasme traduit le Nouveau Testament).", difficulty: 2, points: 10 },
  { id: 'q_2nde_12', level: '2nde', theme: 'Guerres de Religion', question: "Qu'est-ce que l'Édit de Nantes (1598) et pourquoi est-il révoqué en 1685 ?", options: ["Un édit qui interdit le protestantisme en France", "Un édit d'Henri IV accordant la liberté de culte aux protestants — révoqué par Louis XIV qui veut l'uniformité religieuse", "Un traité de paix entre France et Espagne", "Un édit autorisant le divorce en France"], answer: "Un édit d'Henri IV accordant la liberté de culte aux protestants — révoqué par Louis XIV qui veut l'uniformité religieuse", explanation: "L'Édit de Nantes (13 avril 1598) est signé par Henri IV (lui-même ancien protestant converti au catholicisme : 'Paris vaut bien une messe'). Il accorde aux huguenots (protestants français) la liberté de culte, des villes de sûreté et des droits civils. C'est un acte de tolérance rare en Europe. Louis XIV le révoque en 1685 (Édit de Fontainebleau) dans sa quête d'unité nationale (Une foi, une loi, un roi). 200 000 à 400 000 protestants fuient la France (vers l'Angleterre, Prusse, Pays-Bas).", difficulty: 2, points: 10 },
  { id: 'q_2nde_13', level: '2nde', theme: 'Absolutisme', question: "Quels sont les fondements de la monarchie absolue de Louis XIV ?", options: ["Le partage du pouvoir avec le Parlement", "Le pouvoir de droit divin, la centralisation administrative (intendants), Versailles comme instrument de contrôle de la noblesse, la révocation de l'Édit de Nantes", "Une alliance avec la noblesse contre le peuple", "Un pouvoir limité par une Constitution"], answer: "Le pouvoir de droit divin, la centralisation administrative (intendants), Versailles comme instrument de contrôle de la noblesse, la révocation de l'Édit de Nantes", explanation: "Louis XIV (règne personnel 1661-1715) incarne l'absolutisme : 1) Droit divin (il tient son pouvoir de Dieu, théorisé par Bossuet) ; 2) Centralisation (intendants royaux dans les provinces remplacent les nobles locaux) ; 3) Versailles : en y déplaçant la noblesse, il la surveille et la domestique (étiquette, faveurs royales) ; 4) Mercantilisme (Colbert développe l'industrie et le commerce) ; 5) Révocation de l'Édit de Nantes (1685). Sa devise : 'L'État, c'est moi' (même si il ne l'a probablement jamais dit).", difficulty: 2, points: 10 },

  // ========== 1ère — questions supplémentaires ==========
  { id: 'q_1e_15', level: '1ere', theme: 'Régimes totalitaires', question: "Quelle est la différence entre le totalitarisme fasciste et le totalitarisme communiste ?", options: ["Il n'y a aucune différence, ce sont les mêmes régimes", "Le fascisme repose sur le nationalisme, la race et la hiérarchie sociale / le communisme sur la lutte des classes, l'égalité et l'État-parti prolétarien — mais tous deux écrasent les libertés individuelles", "Le communisme est plus violent que le fascisme", "Le fascisme est démocratique et le communisme ne l'est pas"], answer: "Le fascisme repose sur le nationalisme, la race et la hiérarchie sociale / le communisme sur la lutte des classes, l'égalité et l'État-parti prolétarien — mais tous deux écrasent les libertés individuelles", explanation: "Différences idéologiques : Fascisme/nazisme = ultranationalisme, racisme, exaltation de la violence, hierarchie naturelle, capitalisme encadré par l'État. Communisme/URSS = internationalisme prolétarien, lutte des classes, collectivisation, abolition de la propriété. Points communs totalitaires : parti unique, chef charismatique (Mussolini, Hitler, Staline, Mao), terreur politique (GPU/NKVD, Gestapo), propagande permanente, suppression des libertés. Hannah Arendt (Les Origines du totalitarisme, 1951) analyse leurs structures communes.", difficulty: 3, points: 10 },
  { id: 'q_1e_16', level: '1ere', theme: 'Front populaire', question: "Quelles mesures sociales le Front Populaire adopte-t-il en juin 1936 (accords Matignon) ?", options: ["La nationalisations de toutes les entreprises", "Les 40 heures de travail hebdomadaire, 2 semaines de congés payés, augmentation des salaires de 7 à 15% et liberté syndicale", "La suppression du chômage par des grands travaux", "La semaine de 35 heures et la retraite à 60 ans"], answer: "Les 40 heures de travail hebdomadaire, 2 semaines de congés payés, augmentation des salaires de 7 à 15% et liberté syndicale", explanation: "Le Front Populaire (coalition SFIO + Parti radical + PCF) remporte les élections législatives (avril-mai 1936). Léon Blum devient président du Conseil. Face à une vague de grèves générales, les accords Matignon (7 juin 1936) imposent aux patrons : semaine de 40 heures, 2 semaines de congés payés, augmentation des salaires de 7 à 15%, liberté syndicale dans les entreprises. C'est une révolution sociale majeure. Les congés payés permettent aux ouvriers de partir en vacances pour la première fois.", difficulty: 2, points: 10 },
  { id: 'q_1e_17', level: '1ere', theme: 'Décolonisation', question: "Quelle est la différence entre décolonisation pacifique et décolonisation violente ?", options: ["Il n'y a que des décolonisations violentes dans l'Histoire", "Certaines décolonisations se font par négociation (Inde 1947, Maroc 1956), d'autres par la guerre (Algérie 1954-62, Indochine 1945-54, Kenya 1952-60)", "Toutes les décolonisations africaines sont pacifiques", "Les décolonisations violentes n'ont lieu qu'en Asie"], answer: "Certaines décolonisations se font par négociation (Inde 1947, Maroc 1956), d'autres par la guerre (Algérie 1954-62, Indochine 1945-54, Kenya 1952-60)", explanation: "Les décolonisations varient selon plusieurs facteurs : présence ou non de colons européens installés, résistance de la métropole, organisation des mouvements nationalistes. Pacifiques : Inde (Gandhi, non-violence, 1947), Maroc et Tunisie (1956), la plupart des colonies africaines françaises (1960, 'Année de l'Afrique'). Violentes : Algérie (1 million de morts, 1954-62), Indochine-Vietnam (Diên Biên Phu, 1954), Kenya (révolte Mau-Mau, 1952-60), Angola/Mozambique (indépendances portugaises, 1975).", difficulty: 2, points: 10 },

  // ========== Terminale — questions supplémentaires ==========
  { id: 'q_term_08', level: 'Terminale', theme: 'Opinion et médias', question: "Qu'est-ce que la 'société du spectacle' selon Guy Debord (1967) ?", options: ["Une critique de la télévision uniquement", "Une analyse marxiste selon laquelle les relations sociales sont médiées par des images et des représentations — le spectacle est le capital accumulé au degré d'image", "Une théorie sur les médias sociaux", "Une description du cinéma hollywoodien"], answer: "Une analyse marxiste selon laquelle les relations sociales sont médiées par des images et des représentations — le spectacle est le capital accumulé au degré d'image", explanation: "Guy Debord (La Société du spectacle, 1967) développe une critique radicale du capitalisme avancé : la vie sociale est remplacée par une accumulation de spectacles. Les relations authentiques entre personnes sont remplacées par des représentations. La marchandise est devenue image. Debord anticipe l'ère des médias de masse, de la publicité et des réseaux sociaux. Cette œuvre influence Mai 68 (l'Internationale situationniste dont Debord fait partie) et reste une référence critique de la culture de consommation.", difficulty: 3, points: 10 },
  { id: 'q_term_09', level: 'Terminale', theme: 'Géopolitique', question: "Qu'est-ce que le multilatéralisme et pourquoi est-il remis en cause au XXIe siècle ?", options: ["Un système où chaque pays agit seul", "Un système de coopération internationale par des institutions communes (ONU, OMC, FMI) — remis en cause par les nationalismes, le retour des grandes puissances et l'affaiblissement de l'Occident", "Un système économique basé sur plusieurs monnaies", "Un traité militaire entre plusieurs pays"], answer: "Un système de coopération internationale par des institutions communes (ONU, OMC, FMI) — remis en cause par les nationalismes, le retour des grandes puissances et l'affaiblissement de l'Occident", explanation: "Le multilatéralisme est le principe selon lequel les États coopèrent via des institutions communes (ONU, OMC, FMI, CPI, Accords de Paris). Il a structuré l'ordre mondial post-1945. Il est aujourd'hui remis en cause : Trump ('America First', sortie de l'accord de Paris, de l'OMS), Brexit, montée des nationalismes populistes, rivalité USA/Chine qui paralyse le Conseil de Sécurité, refus du Sud global d'accepter les règles fixées par l'Occident. L'ONU est de plus en plus impuissante (guerre en Ukraine).", difficulty: 3, points: 10 },
  { id: 'q_term_10', level: 'Terminale', theme: 'Histoire culturelle', question: "Qu'est-ce que la 'mémoire collective' selon Maurice Halbwachs et comment construit-elle l'identité nationale ?", options: ["La somme des mémoires individuelles d'un groupe", "Un cadre social partagé qui sélectionne, reconstruit et transmet le passé selon les besoins du présent — construisant l'identité d'un groupe ou d'une nation", "La mémoire biologique d'une espèce", "Les archives officielles d'un État"], answer: "Un cadre social partagé qui sélectionne, reconstruit et transmet le passé selon les besoins du présent — construisant l'identité d'un groupe ou d'une nation", explanation: "Maurice Halbwachs (Les Cadres sociaux de la mémoire, 1925) montre que la mémoire n'est pas individuelle mais sociale : on se souvient en groupe, avec des cadres (langage, famille, classe sociale, nation) qui orientent et sélectionnent les souvenirs. La mémoire collective nationale sélectionne des événements fondateurs (1789, Verdun, la Résistance) et en oublie d'autres (Vichy, torture en Algérie). Pierre Nora explore les 'lieux de mémoire' (monuments, commémorations) comme supports de cette identité collective.", difficulty: 3, points: 10 },

  // ========== HGGSP — questions supplémentaires ==========
  { id: 'q_hggsp_09', level: 'HGGSP', theme: 'Espaces maritimes', question: "Qu'est-ce que la Zone Économique Exclusive (ZEE) et pourquoi les États se disputent-ils les océans ?", options: ["Une zone commerciale réservée aux navires marchands", "Une zone de 200 milles marins (370 km) où un État côtier a des droits exclusifs sur les ressources (poissons, pétrole, minerais) — source de conflits croissants", "Une zone militaire interdite aux navires civils", "Un espace international géré par l'ONU"], answer: "Une zone de 200 milles marins (370 km) où un État côtier a des droits exclusifs sur les ressources (poissons, pétrole, minerais) — source de conflits croissants", explanation: "La Convention des Nations Unies sur le droit de la mer (CNUDM, 1982) définit la ZEE : une zone de 200 milles nautiques (370 km) où l'État côtier a des droits souverains sur l'exploration et l'exploitation des ressources naturelles (poissons, hydrocarbures, nodules polymétalliques). Les ZEE couvrent 36% des océans. Les tensions explosent en mer de Chine méridionale (îles Spratleys/Paracels revendiquées par Chine, Vietnam, Philippines, Malaisie, Brunei), en Arctique (ressources sous la glace fondante), en Méditerranée orientale.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_10', level: 'HGGSP', theme: 'Environnement et géopolitique', question: "Comment le changement climatique devient-il un enjeu géopolitique majeur ?", options: ["Le changement climatique n'a aucun impact géopolitique", "Il crée des conflits sur les ressources (eau, terres arables), des flux migratoires climatiques, des tensions sur les responsabilités et les compensations financières entre pays riches et pauvres", "Il provoque uniquement des catastrophes naturelles sans dimension politique", "Il favorise la coopération internationale sans créer de tensions"], answer: "Il crée des conflits sur les ressources (eau, terres arables), des flux migratoires climatiques, des tensions sur les responsabilités et les compensations financières entre pays riches et pauvres", explanation: "Le changement climatique a des dimensions géopolitiques majeures : 1) Conflits sur les ressources : pénuries d'eau (Nil, Mékong), désertification, disparition de terres agricoles → tensions régionales ; 2) Migrations climatiques : 200 millions à 1 milliard de réfugiés climatiques estimés d'ici 2050 ; 3) Tensions Nord-Sud : les pays riches (principal émetteurs historiques) refusent de payer suffisamment pour les 'pertes et préjudices' des pays pauvres (les plus vulnérables) ; 4) Nouvelles opportunités : fonte de l'Arctique → nouvelles routes maritimes, nouvelles ressources.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_11', level: 'HGGSP', theme: 'Démocratie et populisme', question: "Qu'est-ce que le populisme et pourquoi menace-t-il les démocraties libérales ?", options: ["Un mouvement politique défendant les intérêts du peuple et toujours démocratique", "Une idéologie opposant 'le peuple pur' aux 'élites corrompues', anti-institutionnelle et susceptible de dériver vers l'autoritarisme en remettant en cause les contre-pouvoirs", "Un synonyme de démagogie électorale sans danger systémique", "Un courant politique de gauche uniquement"], answer: "Une idéologie opposant 'le peuple pur' aux 'élites corrompues', anti-institutionnelle et susceptible de dériver vers l'autoritarisme en remettant en cause les contre-pouvoirs", explanation: "Selon Cas Mudde, le populisme est une 'idéologie fine' opposant 'le vrai peuple' aux 'élites corrompues'. Il peut être de droite (Trump, Orbán, Meloni, Le Pen) ou de gauche (Podemos, Chavez). Il menace les démocraties libérales car : 1) il remet en cause les contre-pouvoirs (justice indépendante, presse libre, opposition) ; 2) il prétend incarner seul la volonté populaire ; 3) il affaiblit les institutions internationales. Cas : Orbán (Hongrie) crée une 'démocratie illibérale', Trump s'attaque au FBI et à la justice.", difficulty: 3, points: 10 },
  { id: 'q_hggsp_12', level: 'HGGSP', theme: 'Histoire des arts', question: "Comment l'art peut-il être un instrument de propagande politique ?", options: ["L'art ne peut jamais servir la propagande car il exprime la liberté individuelle", "Les régimes totalitaires (nazisme, stalinisme, maoïsme) ont utilisé l'art (peinture, cinéma, architecture) pour glorifier le régime et formater les esprits — mais l'art résiste aussi via l'art engagé", "Seul le cinéma peut servir la propagande", "La propagande artistique n'existe que dans les pays communistes"], answer: "Les régimes totalitaires (nazisme, stalinisme, maoïsme) ont utilisé l'art (peinture, cinéma, architecture) pour glorifier le régime et formater les esprits — mais l'art résiste aussi via l'art engagé", explanation: "Les régimes totalitaires utilisent l'art comme outil de contrôle : le 'réalisme socialiste' soviétique impose une esthétique au service du Parti (ouvriers héroïques, Lénine triomphant) ; Leni Riefenstahl réalise Triumph des Willens (1935) pour glorifier Hitler ; l'architecture nazie monumentalise l'État. En réponse, l'art devient espace de résistance : Picasso peint Guernica (1937) contre les bombardements franquistes ; Chostakovitch résiste musicalement à Staline ; les films de la Nouvelle Vague interrogent la société de consommation.", difficulty: 3, points: 10 },
]

